# timestamp 변환 함수 정의
def to_timestamp(date_str):
    # 형식 파싱 (DDMMYY HH:MM:SS.msec)
    year = int(date_str[:2])
    month = int(date_str[2:4])
    day = int(date_str[4:6])
    hour = int(date_str[7:9])
    minute = int(date_str[10:12])
    second = int(date_str[13:15])
    millisecond = int(date_str[16:19])

    # 연도는 2000년대를 가정 (예: 17 -> 2017)
    year += 2000

    # datetime 객체로 변환
    dt = datetime(year, month, day, hour, minute, second, millisecond * 1000, tzinfo=timezone.utc)
    # Unix Timestamp로 변환 (초 단위)
    return int(dt.timestamp() - 9 * 3600)

# 진행 현황 만드는 함수 (점점 작은 범위로 산정)
def progress(count1, max1, count2, max2, count3, max3):
    progressdata = ((count1 + ((count2 + (count3 / max3) - 1) / max2) - 1) / max1 * 100)
    return progressdata

@dataclass
class CycleGroup:
    """사이클 분석의 단일 그룹 (개별 또는 연결)"""
    name: str                          # 범례/탭 표시명
    paths: list = field(default_factory=list)  # 데이터 경로 목록
    path_names: list = field(default_factory=list)  # per-path cyclename (path 파일 출처)
    is_link: bool = False              # 연결 여부 (paths 2개 이상)
    data_type: str = 'folder'          # 'folder' | 'excel'
    file_idx: int = 0                  # 출처 path 파일 번호
    source_file: str = ''              # 원본 path 파일 경로 (mAh 추출용)
    per_path_channels: list = field(default_factory=list)  # [[ch1],[ch2]] path별 채널 필터 (빈=전체)
    channel_link_map: dict = field(default_factory=dict)  # {norm_ch: unified_sub} 위치 기반 채널 병합 매핑
    per_path_capacities: list = field(default_factory=list)  # [float, ...] path별 테이블 입력 용량 (빈=[])


def _normalize_ch(s):
    """채널번호 정규화: '32' → '032', '032' → '032', 비숫자 → 원본"""
    try:
        return str(int(s)).zfill(3)
    except (ValueError, TypeError):
        return s


def _parse_channel_str(ch_str):
    """채널 문자열 파싱: '32,73,74' → ['032','073','074'], '105,-,-' → ['105','-','-']"""
    if not ch_str or not ch_str.strip():
        return []
    result = []
    for part in ch_str.split(','):
        part = part.strip()
        if part == '-' or part == '':
            result.append('-')
        elif part.isdigit():
            result.append(_normalize_ch(part))
        # 숫자가 아닌 문자열(예: processed_data)은 무시
    return result

# 여러 directory 선택하는 코드
def multi_askopendirnames():
    directories = []
    while True:
        if len(directories) == 0:
            ini_dir = "d://"
        else:
            # 1. 경로 정규화
            normalized_path = os.path.normpath(directories[-1])
            # 2. 상위 디렉토리 추출
            parent_dir = os.path.dirname(normalized_path)
            # 3. 트레일링 백슬래시 추가
            ini_dir = os.path.join(parent_dir, "")  # 빈 문자열과 결합
        directory = filedialog.askdirectory(initialdir=ini_dir, title="원하는 폴더를 계속해서 선택하세요")
        if not directory:
            break
        directories.append(directory)
    return directories

# 대괄호 안의 문자 추출
def _is_channel_folder(name):
    """서브폴더가 채널 폴더인지 판별: [xxx] 형식이거나 순수 숫자 폴더만 True"""
    if re.search(r'\[.*?\]', name):
        return True
    stripped = name.strip()
    return stripped.isdigit()

def extract_text_in_brackets(input_string):
    # 정규 표현식으로 대괄호 안의 문자 추출
    match = re.search(r'\[(.*?)\]', input_string)
    return match.group(1) if match else str(input_string).zfill(3)

def _make_channel_labels(cycnamelist, all_data_name, folder_idx):
    """ch_label(main)과 sub_label을 통일 규칙으로 생성
    - 직접입력: ch_label = cycnamelist[-2] (부모 폴더명)
    - 지정Path: ch_label = all_data_name[folder_idx]
    - sub_label: 항상 extract_text_in_brackets(cycnamelist[-1])
    """
    sub_label = extract_text_in_brackets(cycnamelist[-1])
    if len(all_data_name) != 0:
        ch_label = str(all_data_name[folder_idx]).strip()
    else:
        ch_label = cycnamelist[-2]
    if not ch_label:
        ch_label = cycnamelist[-2]
    # "mAh_" 이후 부분만 추출 (예: "20000mAh_ATL B8 Sub 상온 RSS" → "ATL B8 Sub 상온 RSS")
    if "mAh_" in ch_label:
        ch_label = ch_label.split("mAh_", 1)[1]
    if len(ch_label) > 30:
        ch_label = ch_label[:30] + "..."
    return ch_label, sub_label

# 시리즈를 정해진 갯수의 column으로 분리하는 함수
def separate_series(df_series, num):
    """
    [시리즈 분리 함수]
    - df: 입력 DataFrame의 series
    - num: 분리할 열의 개수
    """
    # 결과 DataFrame 생성 (초기화)
    result_df = pd.DataFrame()
    # 각 값을 적절한 열에 매핑
    for i, value in enumerate(df_series, 1):
        # 열 이름 생성 (예: Column0, Column1, ...)
        col_name = f'col{(i - 1) % num}'
        # 행 인덱스 계산 (예: 0, 1, 2, ...)
        row_idx = (i - 1) // num
        # 값 할당
        result_df.at[row_idx, col_name] = value
    return result_df

# filepath 이름에서 용량을 추출하는 함수
def name_capacity(data_file_path):
    if not isinstance(data_file_path, list):
        # 원시 문자열을 사용하여 특수 문자를 공백으로 대체
        raw_file_path = re.sub(r'[._@\$$$$$$\(\)]', ' ', data_file_path)
        # 정규 표현식을 사용하여 "mAh"로 끝나는 용량 값을 찾습니다. (소수점 포함)
        match = re.search(r'(\d+([\-.]\d+)?)mAh', raw_file_path)
        # 소수점 용량을 위해 -를 .으로 변환
        if match:
            min_cap = match.group(1).replace('-', '.')
        # 일치하는 값이 있으면 실수로 변환하여 반환
            return float(min_cap)
        # 용량 값이 없으면 None을 반환하거나 오류를 발생시킵니다.
        return 0
    else:
        return 0

# 주어진 숫자가 리스트의 몇 번째에 해당하는지 확인하는 코드
def binary_search(numbers, target):
    index = bisect.bisect_left(numbers, target)
    return index

# csv의 마지막 ,를 제거하는 함수
def remove_end_comma(file_path):
    # 파일을 열고 내용을 확인
    with open(file_path, 'r', newline='', encoding='ANSI') as input_file:
        rows = input_file.read().splitlines()
    # 각 줄에 ,가 있으면 제거
    for i, row in enumerate(rows):
        if row.endswith(','):
            rows[i] = row[:-1]
    df = pd.DataFrame(row.split(',') for row in rows)
    return df

