# 랜덤한 값 생성 함수
def generate_params(ca_mass_min, ca_mass_max, ca_slip_min, ca_slip_max, an_mass_min, an_mass_max, an_slip_min, an_slip_max):
    ca_mass = np.random.uniform(ca_mass_min, ca_mass_max)
    ca_slip = np.random.uniform(ca_slip_min, ca_slip_max)
    an_mass = np.random.uniform(an_mass_min, an_mass_max)
    an_slip = np.random.uniform(an_slip_min, an_slip_max)
    return ca_mass, ca_slip, an_mass, an_slip

# 전체 결과 기반 dataframe 생성 함수
def generate_simulation_full(ca_ccv_raw, an_ccv_raw, real_raw, ca_mass, ca_slip, an_mass, an_slip,
                             full_cell_max_cap, rated_cap, full_period):
    # 용량 보정
    ca_ccv_raw.ca_cap_new = ca_ccv_raw.ca_cap * ca_mass - ca_slip
    an_ccv_raw.an_cap_new = an_ccv_raw.an_cap * an_mass - an_slip
    # 기준 용량을 x 기준으로 변경
    simul_full_cap = np.arange(0, full_cell_max_cap, 0.1)
    simul_full_ca_volt = np.interp(simul_full_cap, ca_ccv_raw.ca_cap_new, ca_ccv_raw.ca_volt)
    simul_full_an_volt = np.interp(simul_full_cap, an_ccv_raw.an_cap_new, an_ccv_raw.an_volt)
    simul_full_real_volt = np.interp(simul_full_cap, real_raw.real_cap, real_raw.real_volt)
    # 예측되는 full 셀 전압 계산
    simul_full_volt = simul_full_ca_volt - simul_full_an_volt
    # 전체 결과 데이터프레임 생성
    simul_full = pd.DataFrame({"full_cap": simul_full_cap, "an_volt": simul_full_an_volt,
                               "ca_volt": simul_full_ca_volt, "full_volt": simul_full_volt, "real_volt": simul_full_real_volt})
    simul_full = simul_full.drop(simul_full.index[-1])
    # 백분율로 용량 변경
    simul_full.full_cap = simul_full.full_cap / rated_cap * 100
    # 미분값 생성
    simul_full["an_dvdq"] = simul_full.an_volt.diff(periods = full_period) / simul_full.full_cap.diff(periods = full_period)
    simul_full["ca_dvdq"] = simul_full.ca_volt.diff(periods = full_period) / simul_full.full_cap.diff(periods = full_period)
    simul_full["real_dvdq"] = simul_full.real_volt.diff(periods = full_period) / simul_full.full_cap.diff(periods = full_period)
    simul_full["full_dvdq"] = simul_full["ca_dvdq"] - simul_full["an_dvdq"]
    return simul_full

# 토요 데이터 csv 확인/ 폴더, cycle 순으로 입력
def toyo_read_csv(*args): 
    if len(args) == 1:
        # capacity.log — 캐시 적용
        cache = _get_channel_cache(args[0])
        if 'capacity_log' in cache:
            return cache['capacity_log']
        filepath = args[0] + "\\capacity.log"
        skiprows = 0
    else:
        filepath = args[0] + "\\%06d" % args[1]
        skiprows = 3
    if os.path.isfile(filepath):
        # read the csv file into a pandas dataframe
        dataraw = pd.read_csv(filepath, sep=",", skiprows=skiprows, engine="c", encoding="cp949", on_bad_lines='skip')
        if len(args) == 1:
            cache['capacity_log'] = dataraw
        return dataraw

# Data 처리
# Toyo Profile 불러오기
def toyo_Profile_import(raw_file_path, cycle):
    df = pd.DataFrame()
    df.dataraw = toyo_read_csv(raw_file_path, cycle)
    if hasattr(df, 'dataraw') and not df.dataraw.empty:
        if "PassTime[Sec]" in df.dataraw.columns:
            if "Temp1[Deg]" in df.dataraw.columns:
                # Toyo BLK 3600_3000
                df.dataraw = df.dataraw[["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[Deg]"]]
            else:
            # 신뢰성 충방전기 (Temp 없음)
                df.dataraw = df.dataraw[["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "TotlCycle"]]
                df.dataraw.columns = ["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[Deg]"]
        else:
            # Toyo BLK5200
            df.dataraw = df.dataraw[["Passed Time[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[deg]"]]
            df.dataraw.columns = ["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[Deg]"]
    return df

# Toyo Cycle 불러오기

def toyo_cycle_import(raw_file_path):
    df = pd.DataFrame()
    df.dataraw = toyo_read_csv(raw_file_path)
    if hasattr(df, 'dataraw') and not df.dataraw.empty:
        if "Cap[mAh]" in df.dataraw.columns: 
            df.dataraw = df.dataraw[["TotlCycle", "Condition", "Cap[mAh]", "Ocv", "Finish", "Mode", "PeakVolt[V]",
                                     "Pow[mWh]", "PeakTemp[Deg]", "AveVolt[V]"]]
        else: 
            df.dataraw = df.dataraw[["Total Cycle", "Condition", "Capacity[mAh]", "OCV[V]", "End Factor", "Mode",
                                     "Peak Volt.[V]", "Power[mWh]","Peak Temp.[deg]", "Ave. Volt.[V]"]]
            df.dataraw.columns = ["TotlCycle", "Condition", "Cap[mAh]", "Ocv", "Finish", "Mode", "PeakVolt[V]",
                                  "Pow[mWh]", "PeakTemp[Deg]", "AveVolt[V]"]
    return df

# Toyo min. cap 산정하기 (첫 사이클 전류와 C-rate 이용)
def toyo_min_cap(raw_file_path, mincapacity, inirate):
    # 캐시 확인 (동일 경로에 대해 이미 산정된 용량 재사용)
    if mincapacity == 0:
        cache = _get_channel_cache(raw_file_path)
        if 'min_cap' in cache:
            return cache['min_cap']
        if "mAh" in raw_file_path: # 파일 이름에 용량 관련 문자 있을 때
            mincap = name_capacity(raw_file_path)
        else:
            inicapraw = toyo_read_csv(raw_file_path, 1) # 첫 사이클 기준으로 3번째 줄을 C-rate로 가정하여 용량 환산
            mincap = int(round(inicapraw["Current[mA]"].max()/inirate))
        cache['min_cap'] = mincap
    else: # 표기된 숫자를 용량으로 지정
        mincap = mincapacity
    return mincap    

# Toyo Cycle data 처리
def toyo_cycle_data(raw_file_path, mincapacity, inirate, chkir):
    # 폴더 확인
    # print(raw_file_path)
    df = pd.DataFrame()
    # 용량 산정
    tempmincap = toyo_min_cap(raw_file_path, mincapacity, inirate)
    mincapacity = tempmincap
    # data 기본 처리 (csv data loading)
    tempdata = toyo_cycle_import(raw_file_path)
    if hasattr(tempdata, "dataraw") and not tempdata.dataraw.empty:
        Cycleraw = tempdata.dataraw
        # 기존 cycle 저장
        Cycleraw.loc[:,"OriCycle"]=Cycleraw.loc[:,"TotlCycle"]
        # 방전 시작 시 첫 행(고아 방전) 제거
        # 기존 버그: Condition==2 전체 행의 TotlCycle -= 1 → dcir 파일 조회 등에서 번호 불일치 유발
        # 수정: 고아 첫 행만 드롭. OriCycle이 원본을 보존하고, merge_group은 Condition 시퀀스 기반이므로 TotlCycle 수정 불필요
        if Cycleraw.loc[0, "Condition"] == 2 and len(Cycleraw.index) > 2:
            if Cycleraw.loc[1, "TotlCycle"] == 1:
                Cycleraw = Cycleraw.drop(0, axis=0)
                Cycleraw = Cycleraw.reset_index()
        
        # while loop 변경 260206
        # 연속된 동일 Condition에 그룹
        cond_series = Cycleraw["Condition"]
        merge_group = ((cond_series != cond_series.shift()) | (~cond_series.isin([1, 2]))).cumsum()
        
        def merge_rows(group):
            # 충방전 단일 행 반환
            if len(group) == 1: 
                return group.iloc[0]
            cond = group["Condition"].iloc[0]
            result = group.iloc[-1].copy()  # 마지막 행 기준
            if cond == 1:
                # 충전: Cap 합산, Ocv는 첫 번째 값
                result["Cap[mAh]"] = group["Cap[mAh]"].sum()
                result["Ocv"] = group["Ocv"].iloc[0]
            elif cond == 2:
                # 방전: Cap, Pow 합산, AveVolt 재계산
                result["Cap[mAh]"] = group["Cap[mAh]"].sum()
                result["Pow[mWh]"] = group["Pow[mWh]"].sum()
                result["Ocv"] = group["Ocv"].iloc[0]
                if result["Cap[mAh]"] != 0:
                    result["AveVolt[V]"] = result["Pow[mWh]"] / result["Cap[mAh]"]
            return result
        
        # 병합 전: merge_group 기반 충전 PeakVolt max 및 스텝 수 저장
        _chg_pre = Cycleraw[Cycleraw['Condition'] == 1]
        _mg_chg = merge_group[_chg_pre.index]
        if 'PeakVolt[V]' in _chg_pre.columns and len(_chg_pre) > 0:
            _peak_by_mg = _chg_pre.groupby(_mg_chg)['PeakVolt[V]'].max()
            _peak_by_mg = (_peak_by_mg * 100).round() / 100
            _steps_by_mg = _chg_pre.groupby(_mg_chg).size()
            _last_tc = _chg_pre.groupby(_mg_chg)['TotlCycle'].last()
            _chg_volt_map = pd.Series(_peak_by_mg.values, index=_last_tc.values)
            _chg_steps_map = pd.Series(_steps_by_mg.values, index=_last_tc.values)
        else:
            _chg_volt_map = pd.Series(dtype=float)
            _chg_steps_map = pd.Series(dtype=int)
        # 그룹별로 병합 수행
        Cycleraw = Cycleraw.groupby(merge_group, group_keys=False).apply(merge_rows, include_groups=False)
        Cycleraw = Cycleraw.reset_index(drop=True)
        # 충전 용량 처리
        chgdata = Cycleraw[(Cycleraw["Condition"] == 1) & (Cycleraw["Finish"] != "                 Vol") 
                           & (Cycleraw["Finish"] != "Volt") & (Cycleraw["Cap[mAh]"] > (mincapacity/60))]
        chgdata.index = chgdata["TotlCycle"]
        Chg = chgdata["Cap[mAh]"]
        # 충전 전압/스텝: chgdata 인덱스(TotlCycle)에 맞춰 조회
        _ChgVolt = _chg_volt_map.reindex(chgdata.index)
        _ChgSteps = _chg_steps_map.reindex(chgdata.index).fillna(0).astype(int)
        # Rest End Voltage 추출
        Ocv = chgdata["Ocv"]
        # Cycle raw index 변경
        Cycleraw.index = Cycleraw["TotlCycle"]
        # dcir 계산
        dcir = Cycleraw[((Cycleraw["Finish"] == "                 Tim") | (Cycleraw["Finish"] == "Tim") 
                         | (Cycleraw["Finish"] == "Time")) & (Cycleraw["Condition"] == 2) 
                        & (Cycleraw["Cap[mAh]"] < (mincapacity/60))]
        cycnum = dcir["TotlCycle"]
        # 방전 용량/온도 계산
        Dchgdata = Cycleraw[(Cycleraw["Condition"] == 2) & (Cycleraw["Cap[mAh]"] > (mincapacity/60))]
        Dchg = Dchgdata["Cap[mAh]"]
        Temp= Dchgdata["PeakTemp[Deg]"]
        DchgEng = Dchgdata["Pow[mWh]"]
        AvgV = Dchgdata["AveVolt[V]"]
        OriCycle = Dchgdata.loc[:,"OriCycle"]
        # dcir 기본 처리
        for cycle in cycnum:
            if os.path.isfile(raw_file_path + "\\%06d" % cycle):
                dcirpro = pd.read_csv((raw_file_path + "\\%06d" % cycle), sep=",", skiprows=3, engine="c",
                                      encoding="cp949", on_bad_lines='skip')
                if "PassTime[Sec]" in dcirpro.columns:
                    dcirpro = dcirpro[["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[Deg]"]]
                else:
                    dcirpro = dcirpro[["Passed Time[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[deg]"]]
                    dcirpro.columns = ["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Condition", "Temp1[Deg]"]
                dcircal = dcirpro[(dcirpro["Condition"] == 2)]
                dcir.loc[int(cycle), "dcir"] = ((dcircal["Voltage[V]"].max() - dcircal["Voltage[V]"].min()) 
                                                / round(dcircal["Current[mA]"].max()) * 1000000)
        n = 1
        cyccal = []
        if len(dcir) != 0:
            if (len(Dchg)/(len(dcir)/2)) >= 10:
                dcirstep = (int(len(Dchg)/(len(dcir)/2)/10) + 1) * 10
            else:
                dcirstep = int(len(Dchg)/(len(dcir)/2)) + 1
            for i in range(len(dcir)):
                if chkir:
                    cyccal.append(n)
                    n = n + 1
                else:
                    cyccal.append(n)
                    if i % 2 == 0:
                        n = n + 1
                    else:
                        n = n + dcirstep - 1
        dcir["Cyc"] = cyccal
        dcir = dcir.set_index(dcir["Cyc"])
        # ── 충방전 효율 계산 (병합 후 TotlCycle 인덱스 보정) ──
        # Toyo 병합 시 Chg 인덱스(8,13,18…)와 Dchg 인덱스(9,14,19…)가
        # 1칸씩 어긋나므로, 순서(위치) 기반으로 재정렬하여 매칭
        if len(Dchg) > 0 and len(Chg) > 0:
            # 초기 부분 방전(매칭 충전 없음) 제거
            if Dchg.index[0] < Chg.index[0]:
                Dchg = Dchg.iloc[1:]
                Temp = Temp.iloc[1:]
                DchgEng = DchgEng.iloc[1:]
                AvgV = AvgV.iloc[1:]
                OriCycle = OriCycle.iloc[1:]
            # Chg/Ocv/ChgVolt/ChgSteps를 Dchg 인덱스에 위치 기반 재정렬
            _nmin = min(len(Chg), len(Dchg))
            Chg = pd.Series(Chg.values[:_nmin], index=Dchg.index[:_nmin])
            Ocv = pd.Series(Ocv.values[:_nmin], index=Dchg.index[:_nmin])
            _ChgVolt = pd.Series(_ChgVolt.values[:_nmin], index=Dchg.index[:_nmin])
            _ChgSteps = pd.Series(_ChgSteps.values[:_nmin], index=Dchg.index[:_nmin])
            Dchg = Dchg.iloc[:_nmin]
            Temp = Temp.iloc[:_nmin]
            DchgEng = DchgEng.iloc[:_nmin]
            AvgV = AvgV.iloc[:_nmin]
            OriCycle = OriCycle.iloc[:_nmin]
        Chg2 = Chg.shift(periods=-1)
        Eff = Dchg / Chg
        Eff2 = Chg2 / Dchg
        # 용량 ratio
        Dchg = Dchg/mincapacity
        Chg = Chg/mincapacity
        # 전체 Data 취합
        df.NewData = pd.DataFrame({"Dchg": Dchg, "RndV": Ocv, "Eff": Eff, "Chg": Chg, "DchgEng": DchgEng,
                                   "Eff2": Eff2, "Temp": Temp, "AvgV": AvgV, "OriCyc": OriCycle})
        # Dchg 또는 Chg 중 하나라도 NaN이면 제거 (불완전 사이클)
        df.NewData = df.NewData.dropna(subset=['Dchg', 'Chg'], how='any')
        df.NewData = df.NewData.reset_index()
        if hasattr(dcir, "dcir"):
            df.NewData = pd.concat([df.NewData, dcir["dcir"]], axis=1, join="outer")
        else:
            df.NewData.loc[0, "dcir"] = 0
        df.NewData = df.NewData.drop("TotlCycle", axis=1)
        # ── .ptn 구조 분석 → 논리사이클 힌트 ──
        _ptn_struct = None
        try:
            _ptn_struct = extract_toyo_ptn_structure(raw_file_path, mincapacity)
        except Exception:
            _ptn_struct = None
        # ── 논리사이클 매핑 생성 및 적용 ──
        _cycle_map = None
        try:
            _cycle_map, _ = toyo_build_cycle_map(
                raw_file_path, mincapacity, inirate, ptn_struct=_ptn_struct,
            )
        except Exception:
            _cycle_map = None
        if _cycle_map and len(df.NewData) > 0:
            # Toyo: Cycle 열은 항상 순번 부여 (호환성)
            # cycle_map은 df.cycle_map에 보존 (프로필 파이프라인에서 사용)
            df.NewData.insert(0, "Cycle", range(1, len(df.NewData) + 1))
        else:
            # cycle_map 없음: 기존 방식 (순번)
            df.NewData.insert(0, "Cycle", range(1, len(df.NewData) + 1))
        df.cycle_map = _cycle_map if _cycle_map else {}
        # ── 충전 전용 사이클 df.NewData에 추가 (스윕 시험만) ──
        # 스윕 시험에서 cycle_map에는 있지만 df.NewData에 없는 논리사이클 = 충전 전용 (화성 등)
        # 일반 시험은 순번 부여이므로 cycle_map 키와 Cycle 번호가 불일치 → 스킵
        # Toyo는 Cycle 열이 순번이므로 충전 전용 추가 스킵
        # (cycle_map은 df.cycle_map에 보존되어 프로필 파이프라인에서 사용)
        if False and 'Cycle' in df.NewData.columns:
            _existing_lns = set(df.NewData['Cycle'].values)
            _chg_only_rows: list[dict] = []
            for _ln, _tc_range in _cycle_map.items():
                if _ln in _existing_lns:
                    continue
                # cycle_map 범위 내 충전 데이터 조회
                if isinstance(_tc_range, tuple):
                    _tc_s, _tc_e = _tc_range
                    _match = chgdata[(chgdata.index >= _tc_s) & (chgdata.index <= _tc_e)]
                else:
                    _match = chgdata.loc[[_tc_range]] if _tc_range in chgdata.index else chgdata.iloc[0:0]
                if _match.empty:
                    continue
                _chg_cap_sum = _match["Cap[mAh]"].sum()
                _ocv_val = _match["Ocv"].iloc[-1] if "Ocv" in _match.columns else np.nan
                _ori_tc = int(_match.index[-1])
                _chg_only_rows.append({
                    'Cycle': _ln,
                    'Dchg': np.nan,
                    'RndV': _ocv_val,
                    'Eff': np.nan,
                    'Chg': _chg_cap_sum / mincapacity,
                    'DchgEng': np.nan,
                    'Eff2': np.nan,
                    'Temp': np.nan,
                    'AvgV': np.nan,
                    'OriCyc': _ori_tc,
                })
            if _chg_only_rows:
                _chg_df = pd.DataFrame(_chg_only_rows)
                df.NewData = pd.concat([df.NewData, _chg_df], ignore_index=True)
                df.NewData = df.NewData.sort_values('Cycle').reset_index(drop=True)
        # ── 충전 상한 전압 트래킹: ChgVolt, ChgSteps (위치 기반 정렬) ──
        if len(df.NewData) > 0 and len(_ChgVolt.dropna()) > 0:
            _n = min(len(_ChgVolt), len(df.NewData))
            df.NewData.loc[df.NewData.index[:_n], 'ChgVolt'] = _ChgVolt.values[:_n]
            df.NewData.loc[df.NewData.index[:_n], 'ChgSteps'] = _ChgSteps.values[:_n]
    else:
        df.cycle_map = {}
    return [mincapacity, df]


def toyo_build_cycle_map(raw_file_path, mincapacity, inirate, ptn_struct=None):
    """Toyo capacity.log로부터 논리사이클 → OriCycle 범위 매핑 생성.

    Parameters
    ----------
    raw_file_path : str
        Toyo 채널 경로.
    mincapacity : float
        공칭 용량 (mAh).
    inirate : float
        초기 C-rate.
    ptn_struct : dict | None
        extract_toyo_ptn_structure() 반환값.
        제공 시 min_pulse_cap_mAh로 용량 임계값 보정.
    """
    mincapacity = toyo_min_cap(raw_file_path, mincapacity, inirate)
    tempdata = toyo_cycle_import(raw_file_path)
    if not (hasattr(tempdata, "dataraw") and not tempdata.dataraw.empty):
        return {}, mincapacity

    Cycleraw = tempdata.dataraw.copy()
    Cycleraw["OriCycle"] = Cycleraw["TotlCycle"]

    # 방전 시작 시 첫 행(고아 방전) 제거
    # OriCycle이 원본을 보존하고, merge_group은 Condition 시퀀스 기반이므로 TotlCycle 수정 불필요
    if Cycleraw.iloc[0]["Condition"] == 2 and len(Cycleraw) > 2:
        if Cycleraw.iloc[1]["TotlCycle"] == 1:
            Cycleraw = Cycleraw.drop(0, axis=0).reset_index(drop=True)

    # 연속 동일 Condition 벡터 그룹 (toyo_cycle_data와 동일)
    cond_series = Cycleraw["Condition"]
    merge_group = ((cond_series != cond_series.shift()) | (~cond_series.isin([1, 2]))).cumsum()

    # 그룹별 OriCycle 범위 + 요약 정보 추출
    group_info = Cycleraw.groupby(merge_group).agg(
        TotlCycle=("TotlCycle", "last"),
        Condition=("Condition", "first"),
        Cap=("Cap[mAh]", "sum"),
        OriMin=("OriCycle", "min"),
        OriMax=("OriCycle", "max")
    ).reset_index(drop=True)

    # 방전 그룹 유효 판별 임계값 결정
    # 기본: mincapacity / 60 (공칭의 1/60)
    # .ptn 힌트: min_pulse_cap_mAh가 더 작으면 해당 값 사용 (GITT 펄스 등)
    cap_threshold = mincapacity / 60
    if ptn_struct and ptn_struct.get('min_pulse_cap_mAh', 0) > 0:
        ptn_min = ptn_struct['min_pulse_cap_mAh']
        if ptn_min < cap_threshold:
            cap_threshold = ptn_min * 0.5  # 보수적 마진

    dchg_mask = (group_info["Condition"] == 2) & (group_info["Cap"] > cap_threshold)
    dchg_indices = group_info[dchg_mask].index.tolist()

    # ── 논리 사이클 구성 ──
    # 규칙 1: 충전→방전→(휴지) = 1 논리사이클 (방전 후 휴지 포함)
    # 규칙 2: 충전 전용 그룹 = 독립 논리사이클 (화성 등)
    used_indices: set[int] = set()
    events: list[tuple[int, int]] = []  # (start_OriMin, end_OriMax)

    # Pass 1: 방전 기반 사이클 (충전 + 방전 + 방전 후 휴지)
    for dchg_idx in dchg_indices:
        start_idx = dchg_idx
        end_idx = dchg_idx

        # 직전 그룹이 충전(Condition=1)이면 사이클 시작에 포함
        if dchg_idx > 0 and group_info.loc[dchg_idx - 1, "Condition"] == 1:
            start_idx = dchg_idx - 1
            used_indices.add(dchg_idx - 1)

        # 방전 직후 연속 비충전/비방전 그룹(휴지 등)을 사이클 끝에 포함
        next_idx = dchg_idx + 1
        while (next_idx < len(group_info)
               and group_info.loc[next_idx, "Condition"] not in (1, 2)):
            end_idx = next_idx
            used_indices.add(next_idx)
            next_idx += 1

        used_indices.add(dchg_idx)

        first_file = int(group_info.loc[start_idx, "OriMin"])
        last_file = int(group_info.loc[end_idx, "OriMax"])
        events.append((first_file, last_file))

    # Pass 2: 충전 전용 사이클 (방전 없이 충전만 있는 그룹)
    chg_only_mask = (group_info["Condition"] == 1) & (group_info["Cap"] > mincapacity / 60)
    for idx in group_info[chg_only_mask].index:
        if idx in used_indices:
            continue
        used_indices.add(idx)
        first_file = int(group_info.loc[idx, "OriMin"])
        last_file = int(group_info.loc[idx, "OriMax"])
        # 충전 후 연속 비충전/비방전 그룹(휴지 등)도 포함
        next_idx = idx + 1
        while (next_idx < len(group_info)
               and next_idx not in used_indices
               and group_info.loc[next_idx, "Condition"] not in (1, 2)):
            last_file = int(group_info.loc[next_idx, "OriMax"])
            used_indices.add(next_idx)
            next_idx += 1
        events.append((first_file, last_file))

    # 시작 파일 기준 정렬 → 논리사이클 번호 부여
    events.sort(key=lambda x: x[0])
    cycle_map = {}
    for ln, (start, end) in enumerate(events, start=1):
        cycle_map[ln] = (start, end)

    return cycle_map, mincapacity


# ── 스윕 기반 사이클 매핑 헬퍼 (GITT/DCIR용) ──────────────────────


def _opposite_dirs(d1: str, d2: str) -> bool:
    """충전/방전 방향이 반대인지 판별.

    MIXED는 양방향을 포함하므로 CHG 또는 DCHG와 짝이 될 수 있다.
    MIXED↔MIXED도 병합 대상 (교대 펄스 패턴).
    """
    _PAIRS = {
        ('CHG', 'DCHG'), ('DCHG', 'CHG'),
        ('MIXED', 'CHG'), ('CHG', 'MIXED'),
        ('MIXED', 'DCHG'), ('DCHG', 'MIXED'),
        ('MIXED', 'MIXED'),
    }
    return (d1, d2) in _PAIRS


def _pne_build_sweep_cycle_map(
    pivot: pd.DataFrame,
    all_tcs: list[int],
    mincapacity: float,
) -> dict:
    """스윕 방향 감지 + 그룹핑 → cycle_map 생성 (GITT/DCIR/펄스 시험용).

    알고리즘
    --------
    1. TotlCycle별 유의 여부(significant)와 주 방향(CHG/DCHG/MIXED) 결정
       - 유의 기준: max(ChgCap, DchgCap) ≥ 공칭 용량의 20%
    2. 유의 TC → 충방전 쌍이 있으면 개별 논리사이클 (RPT, 보관 등)
    3. 비유의 TC → 방향 무관하게 연속된 비유의 TC를 하나의 "스윕"으로 묶기
       (펄스 시험의 DCHG→CHG→DCHG 교대 패턴도 단일 스윕)
    4. 인접 반대 방향 스윕 쌍 → 1 논리사이클로 병합 (해당 시에만)

    Parameters
    ----------
    pivot : pd.DataFrame
        TotlCycle × Condition 피벗 (값: μAh 합산).
    all_tcs : list[int]
        전체 TotlCycle 번호 목록 (정렬 완료).
    mincapacity : float
        공칭 용량 (mAh).

    Returns
    -------
    dict
        {논리사이클: int} (단일 TC) 또는 {논리사이클: (시작TC, 끝TC)} (스윕 범위).
    """
    chg_s = pivot["chgCap"].get(1, pd.Series(dtype=float)).reindex(all_tcs).fillna(0)
    dchg_s = pivot["DchgCap"].get(2, pd.Series(dtype=float)).reindex(all_tcs).fillna(0)

    # ── 유의 TC 임계값: 최대 TC 용량의 50% ──
    # 스윕 시험에서는 공칭 용량 기준이 부적절 (반셀 GITT: 공칭 4mAh인데
    # 펄스 41mAh → 전부 유의로 판정되는 문제).
    # 최대 TC 용량 대비 상대 비율로 "풀 사이클급"과 "펄스"를 구분한다.
    max_cap_per_tc = pd.concat([chg_s, dchg_s], axis=1).max(axis=1)
    max_tc_cap = float(max_cap_per_tc.max()) if len(max_cap_per_tc) > 0 else 0
    threshold = max_tc_cap * 0.5

    # ── 1단계: TC별 속성 (유의 여부 + 주 방향) ──
    tc_attrs: list[tuple] = []      # (tc, significant, direction, has_both)
    for tc in all_tcs:
        c, d = float(chg_s[tc]), float(dchg_s[tc])
        sig = max(c, d) >= threshold
        has_both = c > 0 and d > 0
        # 주 방향 결정 (1.5배 비율 기준)
        if c > 0 and d == 0:
            dirn = 'CHG'
        elif d > 0 and c == 0:
            dirn = 'DCHG'
        elif d > 0 and c / d > 1.5:
            dirn = 'CHG'
        elif c > 0 and d / c > 1.5:
            dirn = 'DCHG'
        else:
            dirn = 'MIXED'
        tc_attrs.append((tc, sig, dirn, has_both))

    # ── 2단계: 세그먼트화 (유의 TC = 개별, 비유의 TC = 스윕 누적) ──
    segments: list[dict] = []
    sweep_tcs: list[int] = []
    sweep_dir: str | None = None

    def _flush_sweep() -> None:
        nonlocal sweep_tcs, sweep_dir
        if sweep_tcs:
            segments.append({'kind': 'sweep', 'tcs': list(sweep_tcs), 'dir': sweep_dir})
        sweep_tcs = []
        sweep_dir = None

    for tc, sig, dirn, has_both in tc_attrs:
        if sig:
            _flush_sweep()
            segments.append({'kind': 'sig', 'tcs': [tc], 'dir': dirn, 'has_both': has_both})
        else:
            # 비유의 TC는 방향 전환과 무관하게 연속 스윕으로 누적
            # (펄스 시험: DCHG→CHG→DCHG 교대 패턴도 하나의 스윕 블록)
            if sweep_dir is None:
                sweep_dir = dirn
            elif dirn != sweep_dir and dirn != 'MIXED':
                sweep_dir = 'MIXED'
            sweep_tcs.append(tc)
    _flush_sweep()

    # ── 2.5단계: 유의 TC(has_both) 직후 DCHG 스윕 → 유의 TC에 흡수 ──
    # 방전 마무리 규칙: 풀사이클 유의 TC 직후의 비유의 방전은
    # 해당 사이클의 방전 완료로 간주하여 흡수한다.
    # 예: [sig TC3 충방전] + [sweep DCHG TC4] → TC3에 TC4 흡수
    absorbed: list[dict] = []
    si = 0
    while si < len(segments):
        seg = segments[si]
        if (seg['kind'] == 'sig'
                and seg.get('has_both', False)
                and si + 1 < len(segments)
                and segments[si + 1]['kind'] == 'sweep'
                and segments[si + 1]['dir'] == 'DCHG'):
            # 유의 TC에 후속 DCHG 스윕 흡수 (방전 마무리)
            absorbed.append({
                'kind': 'sig',
                'tcs': seg['tcs'] + segments[si + 1]['tcs'],
                'dir': seg['dir'],
                'has_both': True,
            })
            si += 2
        else:
            absorbed.append(seg)
            si += 1
    segments = absorbed

    # ── 3단계: 인접 반대 방향 스윕 쌍 → 1 논리사이클로 병합 ──
    merged: list[dict] = []
    si = 0
    while si < len(segments):
        seg = segments[si]
        if (seg['kind'] == 'sweep'
                and si + 1 < len(segments)
                and segments[si + 1]['kind'] == 'sweep'
                and _opposite_dirs(seg['dir'], segments[si + 1]['dir'])):
            merged.append({
                'kind': 'paired',
                'tcs': seg['tcs'] + segments[si + 1]['tcs'],
            })
            si += 2
        else:
            merged.append(seg)
            si += 1

    # ── 4단계: cycle_map 변환 ──
    cycle_map: dict = {}
    ln = 0
    for seg in merged:
        tcs = seg['tcs']
        if seg['kind'] == 'sig':
            # 유의 TC: 충방전 쌍 유무와 무관하게 논리사이클로 포함
            # (초기 충전, 단독 RPT 등 has_both=False인 유의 TC도 유효한 이벤트)
            ln += 1
            if len(tcs) >= 2:
                cycle_map[ln] = (int(min(tcs)), int(max(tcs)))
            else:
                cycle_map[ln] = int(tcs[0])
        else:
            # 스윕 또는 쌍 병합된 스윕
            if len(tcs) >= 2:
                ln += 1
                cycle_map[ln] = (int(min(tcs)), int(max(tcs)))
            elif tcs:
                ln += 1
                cycle_map[ln] = int(tcs[0])
    return cycle_map


def pne_build_cycle_map(
    raw_file_path: str,
    mincapacity: float,
    ini_crate: float,
    sch_struct: dict | None = None,
) -> tuple[dict, float]:
    """PNE SaveEndData로부터 논리사이클 → TotlCycle 매핑 생성.

    시험 유형에 따라 두 가지 매핑 전략을 자동 선택한다:
    - **일반 시험** (가속수명, 율별, 보관 등): TotlCycle 단위 1:1 매핑
    - **스윕 시험** (GITT, DCIR 등): 방향 기반 그룹핑으로 스윕 범위 매핑

    판별 우선순위:
    1. sch_struct.sweep_mode (True/False) — .sch 파일 기반 확정 판별
    2. sig_ratio/has_both_ratio 데이터 휴리스틱 — .sch 미제공 또는 미결정 시

    Parameters
    ----------
    raw_file_path : str
        PNE 채널 경로.
    mincapacity : float
        공칭 용량 (mAh). 0이면 자동 산정.
    ini_crate : float
        초기 C-rate (용량 산정용).
    sch_struct : dict | None
        extract_schedule_structure_from_sch() 반환값.
        sweep_mode 키로 모드를 강제 지정 (True/False/None).

    Returns
    -------
    tuple[dict, float]
        (cycle_map, mincapacity).
        cycle_map 값 형태:
        - int: 단일 TotlCycle (일반 시험 또는 유의 TC)
        - tuple[int, int]: (시작TC, 끝TC) 스윕 범위 (GITT/DCIR)
    """
    if (raw_file_path[-4:-1]) == "ter":
        return {}, mincapacity

    mincapacity = pne_min_cap(raw_file_path, mincapacity, ini_crate)
    if not mincapacity:  # None 또는 0 → threshold=0 되어 모든 TC가 유의로 판정됨
        return {}, 0

    # SaveEndData 캐시 조회
    save_end_cached, _, _ = _cached_pne_restore_files(raw_file_path)
    if save_end_cached is None:
        return {}, mincapacity

    Cycleraw = save_end_cached[[27, 2, 10, 11]].copy()
    Cycleraw.columns = ["TotlCycle", "Condition", "chgCap", "DchgCap"]

    # TotlCycle × Condition 피벗
    pivot = Cycleraw.pivot_table(
        index="TotlCycle",
        columns="Condition",
        values=["DchgCap", "chgCap"],
        aggfunc="sum",
    )
    all_tcs = sorted(Cycleraw["TotlCycle"].unique())
    if not all_tcs:
        return {}, mincapacity

    # ── 시험 유형 판별: .sch 힌트 우선 → 데이터 휴리스틱 폴백 ──
    # 1차: .sch 기반 모드 확정 (있으면)
    _sch_sweep = sch_struct.get('sweep_mode') if isinstance(sch_struct, dict) else None

    # 2차: 데이터 기반 유의 TC 비율 (1차 미결정 시 사용)
    threshold = mincapacity * 1000 * 0.2  # μAh 단위 (공칭 20%)
    chg_s = pivot["chgCap"].get(1, pd.Series(dtype=float)).reindex(all_tcs).fillna(0)
    dchg_s = pivot["DchgCap"].get(2, pd.Series(dtype=float)).reindex(all_tcs).fillna(0)
    max_cap = pd.concat([chg_s, dchg_s], axis=1).max(axis=1)
    n_significant = int((max_cap >= threshold).sum())
    sig_ratio = n_significant / len(all_tcs)

    # has_both 비율: 충방전 쌍이 모두 있는 TC의 비율
    # 낮으면 단방향 펄스 시험 (GITT 반셀 등) → 스윕 모드로 처리해야 함
    has_both_mask = (chg_s > 0) & (dchg_s > 0)
    has_both_ratio = float(has_both_mask.sum()) / len(all_tcs) if all_tcs else 0

    # 보관/소규모 시험 특수 처리: TC ≤ 5이면 스윕 판별 무의미 → 일반 모드 강제
    if len(all_tcs) <= 5 and _sch_sweep is None:
        _sch_sweep = False

    # 최종 모드 결정
    _use_general = (
        _sch_sweep is False  # .sch 또는 보관 특수 처리 → 일반
        or (_sch_sweep is None and sig_ratio >= 0.5 and has_both_ratio >= 0.3)  # 데이터 휴리스틱 → 일반
    )

    if _use_general:
        # ── 일반 시험: TotlCycle 단위 1:1 매핑 ──
        # 조건: 유의 TC가 과반 AND 충방전 쌍이 있는 TC가 30% 이상
        if 2 in pivot["DchgCap"].columns:
            dchg_cap = pivot["DchgCap"][2]
        else:
            dchg_cap = pd.Series(dtype=float)
        if 1 in pivot["chgCap"].columns:
            chg_cap = pivot["chgCap"][1]
        else:
            chg_cap = pd.Series(dtype=float)

        # 충방전 쌍이 있는 TC (기존 동작)
        valid_dchg_tcs = set()
        if not dchg_cap.empty:
            _dchg_valid = dchg_cap.dropna().index
            if not chg_cap.empty:
                _chg_valid = chg_cap.dropna().index
                valid_dchg_tcs = set(_dchg_valid.intersection(_chg_valid))
            else:
                valid_dchg_tcs = set(_dchg_valid)

        # 충전 전용 TC (방전 없이 충전만 있는 TC) — 화성 등 독립 사이클
        chg_only_tcs = set()
        if not chg_cap.empty:
            _all_chg = set(chg_cap.dropna().index)
            _all_dchg = set(dchg_cap.dropna().index) if not dchg_cap.empty else set()
            chg_only_tcs = _all_chg - _all_dchg

        valid_totl_cycles = sorted(valid_dchg_tcs | chg_only_tcs)
        if not valid_totl_cycles:
            return {}, mincapacity

        # 유의 TC 집합 (풀사이클급: 공칭 20% 이상)
        sig_set = set()
        for tc in valid_totl_cycles:
            if float(max_cap.get(tc, 0)) >= threshold:
                sig_set.add(tc)

        # cycle_map 생성: 유의 TC는 개별, 비유의 연속 TC는 스윕 그룹
        # 충전전용 유의 TC + 직후 비유의 블록 → 하나의 스윕으로 병합
        # (풀충전은 펄스 스윕의 준비 단계이므로 물리적으로 같은 이벤트)
        cycle_map = {}
        ln = 0
        i = 0
        while i < len(valid_totl_cycles):
            tc = valid_totl_cycles[i]
            if tc in sig_set:
                # 충전전용 유의 TC 뒤에 비유의 블록 → 함께 묶기
                if (tc in chg_only_tcs
                        and i + 1 < len(valid_totl_cycles)
                        and valid_totl_cycles[i + 1] not in sig_set):
                    group = [tc]
                    i += 1
                    while i < len(valid_totl_cycles) and valid_totl_cycles[i] not in sig_set:
                        group.append(valid_totl_cycles[i])
                        i += 1
                    ln += 1
                    cycle_map[ln] = (int(min(group)), int(max(group)))
                else:
                    ln += 1
                    cycle_map[ln] = int(tc)
                    i += 1
            else:
                # 연속 비유의 TC 블록을 하나의 논리사이클(스윕)로 묶기
                group = [tc]
                i += 1
                while i < len(valid_totl_cycles) and valid_totl_cycles[i] not in sig_set:
                    group.append(valid_totl_cycles[i])
                    i += 1
                ln += 1
                if len(group) == 1:
                    cycle_map[ln] = int(group[0])
                else:
                    cycle_map[ln] = (int(min(group)), int(max(group)))
        return cycle_map, mincapacity
    else:
        # ── 스윕 시험: 방향 기반 그룹핑으로 스윕 범위 매핑 ──
        # .sch sweep_mode=True 확정, 또는 데이터 휴리스틱 (sig_ratio < 0.5 / has_both < 0.3)
        # GITT, DCIR 등 펄스 시험: 연속 동일 방향 TC를 하나의 스윕으로 묶고,
        # 인접 반대 방향 스윕 쌍을 1 논리사이클로 병합
        cycle_map = _pne_build_sweep_cycle_map(pivot, all_tcs, mincapacity)
        return cycle_map, mincapacity


# ═══════════════════════════════════════════════════════════════════
# 사이클 카테고리 분류 (경로별 RPT / Rss / 가속수명 / GITT / initial 판별)
# ═══════════════════════════════════════════════════════════════════

CATEGORY_LABELS = {
    'RPT': 'RPT (0.2C 충방전)',
    'Rss': 'Rss (DCIR pulse)',
    '가속수명': '가속수명 (멀티스텝 충전)',
    'GITT': 'GITT (펄스 그룹)',
    'initial': 'initial (초기 반사이클)',
    'unknown': 'unknown (분류불가)',
}


def _classify_single_pne_cycle(group: pd.DataFrame) -> dict:
    """단일 PNE raw cycle의 기본 정보 및 카테고리 분류."""
    n_charge = int((group['StepType'] == 1).sum())
    n_discharge = int((group['StepType'] == 2).sum())
    n_rest = int((group['StepType'] == 3).sum())
    has_es78 = 78 in group['EndState'].values
    total_steps = len(group)

    # 주 동작: REST 제외 후 어떤 동작인지 판별
    active_steps = [int(s) for s in group['StepType'].values if int(s) in (1, 2)]
    if not active_steps:
        action = 'REST_ONLY'
    elif all(s == 1 for s in active_steps):
        action = 'CHG_ONLY'
    elif all(s == 2 for s in active_steps):
        action = 'DCHG_ONLY'
    else:
        action = 'MIXED'

    if n_charge == 0 and n_discharge == 0:
        cat = 'initial'
    elif action in ('CHG_ONLY', 'DCHG_ONLY'):
        cat = '_pulse'  # GITT 병합 대상
    elif has_es78 and n_charge >= 2 and n_discharge >= 2:
        cat = 'DCIR'  # DCIR 용량구분 또는 GITT 측정
    elif has_es78:
        cat = 'Rss'
    elif n_charge >= 2 and n_discharge >= 1:
        # n_charge==2인 경우: CC+CV 단일 CCCV인지, 실제 다스텝 충전인지 구분
        # EndState 65=전압도달(CC끝), 66=전류도달(CV끝)
        # 단일 CCCV: CC(ES=65) + CV(ES=66) = n_charge=2 → RPT
        # 2스텝 가속수명: CC1+CV1+CC2+CV2 = n_charge=4+ → 가속수명
        chg_rows = group[group['StepType'] == 1]
        chg_es = set(int(e) for e in chg_rows['EndState'].values)
        # 충전 스텝이 정확히 2개이고 CC+CV 쌍(ES=65,66)이면 단일 CCCV → RPT
        if n_charge == 2 and 65 in chg_es and 66 in chg_es:
            cat = 'RPT'
        else:
            cat = '가속수명'
    elif n_charge == 1 and n_discharge >= 1:
        cat = 'RPT'
    else:
        cat = 'unknown'

    return {
        'n_charge': n_charge, 'n_discharge': n_discharge, 'n_rest': n_rest,
        'total_steps': total_steps, 'has_es78': has_es78,
        'action': action, 'category': cat,
    }


def _merge_pulse_groups(raw_results: list[dict]) -> list[dict]:
    """연속 동일 동작 펄스(_pulse)를 GITT 논리 사이클로 병합."""
    if not raw_results:
        return []

    # 1단계: 연속 _pulse 그룹화
    segments: list[tuple] = []
    for r in raw_results:
        if r['category'] == '_pulse':
            if segments and segments[-1][0] == 'pulse' and segments[-1][2] == r['action']:
                segments[-1][1].append(r)
            else:
                segments.append(('pulse', [r], r['action']))
        else:
            segments.append(('normal', [r], None))

    # 2단계: 인접 펄스 그룹 쌍 → GITT 논리 사이클로 병합
    merged = []
    si = 0
    while si < len(segments):
        seg_type, items, action = segments[si]
        if seg_type == 'normal':
            for r in items:
                merged.append(r)
            si += 1
            continue

        paired_items = list(items)
        has_multi_pulse = len(items) >= 2
        if (si + 1 < len(segments)
                and segments[si + 1][0] == 'pulse'
                and segments[si + 1][2] != action):
            si += 1
            paired_items.extend(segments[si][1])
            if len(segments[si][1]) >= 2:
                has_multi_pulse = True

        if not has_multi_pulse:
            for r in paired_items:
                r['category'] = 'initial'
                merged.append(r)
            si += 1
            continue

        raw_cycles = [r['cycle'] for r in paired_items]
        merged.append({
            'cycle': raw_cycles[0],
            'category': 'GITT',
            'n_charge': sum(r['n_charge'] for r in paired_items),
            'n_discharge': sum(r['n_discharge'] for r in paired_items),
            'n_rest': sum(r['n_rest'] for r in paired_items),
            'total_steps': sum(r['total_steps'] for r in paired_items),
            'raw_cycles': len(paired_items),
            'raw_range': f'{min(raw_cycles)}-{max(raw_cycles)}',
        })
        si += 1

    return merged


def classify_pne_cycles(df: pd.DataFrame, capacity: int) -> list[dict]:
    """PNE SaveEndData 기반 사이클별 카테고리 분류.

    분류 기준 (StepType==8 루프마커 제외 후):
      - 충전+방전 포함, n_charge >= 2  → 가속수명
      - 충전+방전 포함, EndState==78    → Rss
      - 충전+방전 포함, n_charge == 1   → RPT
      - 단일 동작 펄스 반복             → GITT
      - 방전만                          → initial
    """
    real = df[df['StepType'] != 8].copy()
    raw_results = []
    for cyc, group in real.groupby('TotlCycle'):
        info = _classify_single_pne_cycle(group)
        info['cycle'] = int(cyc)
        raw_results.append(info)

    merged = _merge_pulse_groups(raw_results)
    results = []
    for r in merged:
        entry = {
            'cycle': r['cycle'],
            'category': r['category'],
            'n_charge': r['n_charge'],
            'n_discharge': r['n_discharge'],
        }
        if 'raw_cycles' in r:
            entry['raw_cycles'] = r['raw_cycles']
            entry['raw_range'] = r['raw_range']
        results.append(entry)
    return results


def classify_toyo_cycles(df: pd.DataFrame, capacity: int) -> list[dict]:
    """Toyo CAPACITY.LOG 기반 사이클별 카테고리 분류.

    분류 기준 (충전 행 수 기반):
      - chg_rows == 0 → initial
      - chg_rows == 1 → RPT
      - chg_rows >= 2 → 가속수명
    """
    results = []
    if df is None or df.empty:
        return results

    conds = df['Condition'].values
    caps = df['Cap[mAh]'].values

    # 연속 동일 Condition 병합
    groups = []
    i = 0
    while i < len(df):
        start = i
        cond = int(conds[i])
        while i < len(df) and int(conds[i]) == cond:
            i += 1
        total_cap = float(caps[start:i].sum())
        n_rows = i - start
        groups.append((cond, n_rows, total_cap))

    gi = 0
    cycle_num = 0
    while gi < len(groups):
        cond, n, cap = groups[gi]
        if cond == 1:
            chg_rows, chg_cap = n, cap
            if gi + 1 < len(groups) and groups[gi + 1][0] == 2:
                dchg_rows, dchg_cap = groups[gi + 1][1], groups[gi + 1][2]
                gi += 2
            else:
                dchg_rows, dchg_cap = 0, 0.0
                gi += 1
        elif cond == 2:
            chg_rows, chg_cap = 0, 0.0
            dchg_rows, dchg_cap = n, cap
            gi += 1
        else:
            gi += 1
            continue

        cycle_num += 1
        if chg_rows == 0:
            cat = 'initial'
        elif chg_rows == 1:
            cat = 'RPT'
        elif chg_rows >= 2:
            cat = '가속수명'
        else:
            cat = 'unknown'

        results.append({
            'cycle': cycle_num,
            'category': cat,
            'chg_rows': chg_rows,
            'dchg_rows': dchg_rows,
            'chg_cap': round(chg_cap, 1),
            'dchg_cap': round(dchg_cap, 1),
        })
    return results


def detect_schedule_pattern(classified: list[dict]) -> str:
    """카테고리 시퀀스의 RLE → 패턴 문자열 생성."""
    if not classified:
        return ''
    categories = [c['category'] for c in classified]
    rle = []
    current = categories[0]
    count = 1
    for cat in categories[1:]:
        if cat == current:
            count += 1
        else:
            rle.append((current, count))
            current = cat
            count = 1
    rle.append((current, count))
    parts = [f'{cat}×{n}' if n > 1 else cat for cat, n in rle]
    return ' → '.join(parts)


def detect_test_type(counts: dict) -> str:
    """카테고리 분포로 시험 종류 추정."""
    total = sum(counts.values())
    if total == 0:
        return '데이터 없음'
    accel = counts.get('가속수명', 0)
    rss = counts.get('Rss', 0)
    rpt = counts.get('RPT', 0)
    gitt = counts.get('GITT', 0)
    if gitt > total * 0.3:
        return 'GITT 시험'
    if accel > total * 0.5:
        return '가속수명 시험'
    if rss > total * 0.3:
        return 'Rss/DCIR 시험'
    if rpt > total * 0.5:
        return 'RPT 전용'
    if accel > 0 and rss > 0:
        return '가속수명 + Rss 복합'
    return '기타'


def _parse_capacity_value(text: str) -> float:
    """용량 문자열 파싱 — 하이픈 소수점 표기 지원.

    '4-22' → 4.22, '4.22' → 4.22, '1689' → 1689.0 등.
    숫자 사이 하이픈을 소수점으로 해석한다 (예: 배터리 명명 규칙 '4-22mAh').
    파싱 실패 시 0.0 반환.
    """
    if not text or not text.strip():
        return 0.0
    s = text.strip()
    # 'mAh' 접미사 제거
    s = re.sub(r'\s*mAh\s*$', '', s, flags=re.IGNORECASE)
    # 숫자-숫자 패턴: 하이픈 → 소수점 (예: 4-22 → 4.22)
    s = re.sub(r'^(\d+)-(\d+)$', r'\1.\2', s)
    try:
        return float(s)
    except ValueError:
        return 0.0


def _extract_capacity_from_path(path: str) -> float:
    """경로 문자열에서 용량(mAh) 추출.

    폴더 명명 규칙 '_XXXXmAh_' 패턴에서 숫자 부분을 추출한다.
    예: '1689mAh' → 1689.0, '2335mAh' → 2335.0, '4-22mAh' → 4.22
    매칭 실패 시 0.0 반환.
    """
    import re
    # 폴더명에서 '숫자+mAh' 패턴 검색 (하이픈 소수점 포함, 대소문자 무시)
    m = re.search(r'(\d+(?:[.\-]\d+)?)\s*mAh', path, re.IGNORECASE)
    if m:
        return _parse_capacity_value(m.group(1))
    return 0.0


def classify_channel_path(channel_path: str, capacity: float = 0) -> dict | None:
    """단일 채널 폴더의 사이클 카테고리를 분류.

    Parameters
    ----------
    channel_path : str
        채널 폴더 경로 (예: rawdata/dataset/[032])
    capacity : float
        추정 용량(mAh). 0이면 폴더명에서 자동 추출 시도.

    Returns
    -------
    dict | None
        {
            'cycler': 'Toyo' | 'PNE',
            'total_cycles': int,
            'counts': {'RPT': n, '가속수명': n, ...},
            'classified': [{'cycle': 1, 'category': 'RPT', ...}, ...],
            'schedule_pattern': str,
            'test_type': str,
        }
    """
    # Pattern 폴더는 채널 서브폴더가 아닌 상위 데이터 경로에 있음
    parent_path = os.path.dirname(channel_path)
    is_pne = check_cycler(parent_path)

    # capacity가 0이면 폴더명에서 자동 추출 시도
    if not capacity:
        capacity = _extract_capacity_from_path(parent_path)

    _raw_df = None  # CSV 원본 (analyze_accel_pattern 재사용)
    if is_pne:
        # PNE: SaveEndData.csv 로딩 — 캐시 사용
        _raw_df, _, _ = _cached_pne_restore_files(channel_path)
        if _raw_df is None:
            return None
        if _raw_df.shape[1] < 28:
            return None
        summary = _raw_df[[27, 2, 6, 9, 10, 11, 17]].copy()
        summary.columns = ['TotlCycle', 'StepType', 'EndState', 'Current', 'ChgCap', 'DchgCap', 'StepTime']
        classified = classify_pne_cycles(summary, int(capacity))
    else:
        # Toyo: capacity.log 로딩 — 캐시 사용
        _raw_df = toyo_read_csv(channel_path)
        if _raw_df is None:
            # 대소문자 차이 허용 (capacity.log가 아닌 경우)
            cap_log_path = os.path.join(channel_path, 'capacity.log')
            for f in os.listdir(channel_path):
                if f.upper() == 'CAPACITY.LOG':
                    cap_log_path = os.path.join(channel_path, f)
                    break
            else:
                return None
            try:
                _raw_df = pd.read_csv(cap_log_path, sep=',', encoding='cp949', on_bad_lines='skip')
            except Exception:
                return None
        needed = ['Condition', 'TotlCycle', 'Cap[mAh]']
        if not all(c in _raw_df.columns for c in needed):
            return None
        classified = classify_toyo_cycles(_raw_df[['Condition', 'TotlCycle', 'Cap[mAh]']].copy(), int(capacity))

    if not classified:
        return None

    counts = {}
    for c in classified:
        cat = c['category']
        counts[cat] = counts.get(cat, 0) + 1

    # .sch 우선 전략: PNE + 파서 있으면 .sch에서 test_type, pattern 결정
    sch_struct = None
    if is_pne and HAS_SCH_PARSER:
        sch_file = _find_sch_file(channel_path)
        if sch_file:
            sch_struct = extract_schedule_structure_from_sch(sch_file, capacity)

    if sch_struct:
        # .sch 기반 (설계 의도)
        test_type = sch_struct['schedule_type']
        schedule_pattern = sch_struct['pattern_string']
    else:
        # CSV 폴백 (Toyo 또는 .sch 없는 경우)
        test_type = detect_test_type(counts)
        schedule_pattern = detect_schedule_pattern(classified)

    result = {
        'cycler': 'PNE' if is_pne else 'Toyo',
        'total_cycles': len(classified),
        'counts': counts,
        'classified': classified,
        'schedule_pattern': schedule_pattern,
        'test_type': test_type,
    }

    # .sch 구조 정보 첨부 (있는 경우)
    if sch_struct:
        result['sch_info'] = {
            'has_rss': sch_struct['has_rss'],
            'has_gitt_hppc': sch_struct['has_gitt_hppc'],
            'pattern_string': sch_struct['pattern_string'],
            'schedule_type': sch_struct['schedule_type'],
        }

    # 가속수명 충방전 패턴 분석 (이미 로딩한 CSV 재사용)
    accel_pattern = analyze_accel_pattern(
        channel_path, capacity, classified, is_pne, raw_df=_raw_df,
    )
    if accel_pattern:
        result['accel_pattern'] = accel_pattern

    return result


def classify_paths_summary(path_list: list, capacity_list: list | None = None) -> dict:
    """여러 경로의 사이클 분류를 일괄 수행하여 요약 dict 반환.

    Parameters
    ----------
    path_list : list[str]
        상위 데이터 경로 목록 (각 경로 안에 채널 서브폴더 탐색)
    capacity_list : list[float] | None
        경로별 용량 (mAh), None이면 모두 0(자동 감지)

    Returns
    -------
    dict
        {
            'channels': [{'path': str, 'channel': str, ...classify result...}, ...],
            'summary_text': str,  # 콘솔 출력용 요약 문자열
        }
    """
    results = []
    for idx, data_path in enumerate(path_list):
        cap = capacity_list[idx] if capacity_list and idx < len(capacity_list) else 0
        if not os.path.isdir(data_path):
            continue
        # 채널 서브폴더 탐색
        try:
            subfolders = [f.path for f in os.scandir(data_path)
                          if f.is_dir() and _is_channel_folder(f.name)]
        except OSError:
            continue
        for ch_path in subfolders:
            if 'Pattern' in os.path.basename(ch_path):
                continue
            result = classify_channel_path(ch_path, cap)
            if result:
                result['path'] = data_path
                result['channel'] = os.path.basename(ch_path)
                results.append(result)

    # 요약 텍스트 생성
    lines = []
    if results:
        lines.append('─' * 60)
        lines.append('  사이클 카테고리 분류 결과')
        lines.append('─' * 60)
        for r in results:
            ch_name = r['channel']
            test_type = r['test_type']
            total = r['total_cycles']
            counts = r['counts']
            cat_parts = []
            for cat in ['RPT', 'Rss', '가속수명', 'GITT', 'initial', 'unknown']:
                n = counts.get(cat, 0)
                if n > 0:
                    cat_parts.append(f'{cat}:{n}')
            lines.append(f'  [{r["cycler"]}] {ch_name}  |  {test_type}  |  총 {total}cyc  |  {", ".join(cat_parts)}')
            if r['schedule_pattern']:
                lines.append(f'         패턴: {r["schedule_pattern"]}')
        lines.append('─' * 60)

    return {
        'channels': results,
        'summary_text': '\n'.join(lines),
    }


# ═══════════════════════════════════════════════════════════════════
# 가속수명 충방전 패턴 분석 (스텝 수, C-rate, CC/CCCV cutoff)
# ═══════════════════════════════════════════════════════════════════

# 표준 C-rate 그리드 (배터리 시험에서 사용되는 대표값)
_CRATE_GRID = [
    0.02, 0.05, 0.1, 0.15, 0.2, 0.25, 0.3, 0.33, 0.4, 0.5,
    0.6, 0.65, 0.7, 0.75, 0.8, 0.9, 1.0, 1.2, 1.4, 1.5,
    1.65, 2.0, 2.8,
]


def _snap_crate(raw: float, tolerance: float = 0.05) -> float:
    """원시 C-rate를 표준 그리드 가장 가까운 값으로 스냅.

    tolerance 비율(기본 5%) 이내에 그리드 값이 있으면 스냅,
    없으면 0.05C 단위로 반올림한다.
    """
    if raw <= 0:
        return 0.0
    best_val = raw
    best_rel = tolerance + 1  # 초기값: 허용 범위 밖
    for g in _CRATE_GRID:
        rel = abs(raw - g) / g
        if rel < best_rel:
            best_rel = rel
            best_val = g
    if best_rel <= tolerance:
        return best_val
    # 그리드에 매칭 안 되면 0.05C 단위 반올림
    return round(round(raw / 0.05) * 0.05, 2)


def _snap_voltage(raw: float) -> float:
    """원시 전압을 0.01V 단위로 반올림 (센서 미세 오차 보정).

    Python round()의 부동소수점 오차 방지를 위해 Decimal 사용.
    """
    from decimal import Decimal, ROUND_HALF_UP
    return float(Decimal(str(raw)).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))


# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
#   Toyo PTN 파일 파서
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━


def _find_ptn_file(channel_path: str) -> str | None:
    """채널 폴더에서 .PTN 메인 파일 경로를 반환. 없으면 None.

    _Option.PTN, _Option2.PTN 은 제외한다.
    """
    try:
        for f in os.listdir(channel_path):
            if f.upper().endswith('.PTN') and '_Option' not in f:
                return os.path.join(channel_path, f)
    except OSError:
        pass
    return None


def _read_ptn_option_capacity(channel_path: str) -> float:
    """_Option.PTN 에서 BaseCellCapacity(mAh) 읽기. 실패 시 0."""
    try:
        for f in os.listdir(channel_path):
            if '_Option.PTN' in f and 'Option2' not in f:
                opt_path = os.path.join(channel_path, f)
                with open(opt_path, 'r', encoding='utf-8', errors='replace') as fh:
                    for line in fh:
                        if 'BaseCellCapacity=' in line:
                            val = line.split('=', 1)[1].strip()
                            return float(val)
    except (OSError, ValueError):
        pass
    return 0.0


def _parse_ptn_step(line: str) -> dict:
    """PTN 스텝 라인(543+ chars) 파싱 → 충전/방전/루프 정보 딕셔너리.

    Toyo PTN 고정폭 필드 위치 (검증 완료):
      충전측: mode[1:4] cur[5:15] cv_v[17:23] cc_endv[32:39] cutoff[55:63] rest[106:111]
      방전측: mode[262:266] cur[268:276] endv[311:318] rest[361:366]
      루프:   loop_to[535:539] loop_count[539:543]
      모드코드: 00=CC, 10=CCCV, 30=Rest
    """
    def _f(s: str) -> float:
        """공백/대시 제거 후 float 변환. 실패 시 0."""
        v = s.strip().replace('-', '')
        try:
            return float(v) if v else 0.0
        except ValueError:
            return 0.0

    chg_mode_raw = line[1:4].strip()
    dchg_mode_raw = line[262:266].strip()

    # 모드 해석
    _MODE = {'00': 'CC', '10': 'CCCV', '30': 'Rest'}
    chg_mode = _MODE.get(chg_mode_raw, 'Unknown')
    dchg_mode = _MODE.get(dchg_mode_raw, 'Unknown')

    return {
        'chg_mode': chg_mode,
        'chg_current_mA': _f(line[5:15]),
        'chg_cv_voltage': _f(line[17:23]),
        'chg_cc_endvolt': _f(line[32:39]),
        'chg_cutoff_mA': _f(line[55:63]),
        'chg_rest_min': _f(line[106:111]),
        'dchg_mode': dchg_mode,
        'dchg_current_mA': _f(line[268:276]),
        'dchg_endvolt': _f(line[311:318]),
        'dchg_rest_min': _f(line[361:366]),
        'loop_to': int(_f(line[535:539])),
        'loop_count': int(_f(line[539:543])),
    }


def _parse_toyo_ptn(
    channel_path: str, capacity: float,
) -> dict | None:
    """Toyo .PTN 파일에서 가속수명 충방전 패턴 정보 추출.

    PTN 파일의 루프 구간을 식별하여 첫 번째 루프 그룹의
    충전/방전 스텝별 CC/CCCV 모드, C-rate, cutoff 전압/전류를 반환한다.
    복수 루프 그룹(전압 step-down)이 있으면 전압 변경 정보도 포함.

    Parameters
    ----------
    channel_path : str
        채널 폴더 경로 (.PTN 파일이 있는 폴더)
    capacity : float
        공칭 용량 (mAh)

    Returns
    -------
    dict | None
        analyze_accel_pattern 호환 형식:
        {
            'charge_steps': [...],
            'discharge_steps': [...],
            'n_charge_steps': int,
            'n_discharge_steps': int,
            'voltage_schedule': [(loop_idx, chg_max_v, loop_count), ...],
        }
    """
    ptn_file = _find_ptn_file(channel_path)
    if not ptn_file:
        return None

    try:
        with open(ptn_file, 'r', encoding='utf-8', errors='replace') as fh:
            lines = fh.readlines()
    except OSError:
        return None
    if len(lines) < 3:
        return None

    # Option 파일에서 용량 읽기 (인자 capacity가 0이면 대체)
    ptn_cap = _read_ptn_option_capacity(channel_path)
    if ptn_cap > 0:
        capacity = ptn_cap

    # 모든 스텝 파싱
    steps: list[dict] = []
    for line in lines[1:]:
        if len(line) < 100:
            continue
        steps.append(_parse_ptn_step(line))

    if not steps:
        return None

    # 루프 그룹 식별: loop_to > 0 인 스텝이 루프 종점
    # 루프 범위 = [loop_to, current_step] (1-based → 0-based 보정)
    loop_groups: list[tuple[int, int, int]] = []  # (start_idx, end_idx, loop_count)
    for i, s in enumerate(steps):
        if s['loop_to'] > 0:
            start = s['loop_to'] - 1  # 1-based → 0-based
            loop_groups.append((start, i, s['loop_count']))

    if not loop_groups:
        return None

    # 첫 번째 루프 그룹에서 충전/방전 스텝 추출
    lg_start, lg_end, _ = loop_groups[0]
    accel_steps = steps[lg_start:lg_end + 1]

    charge_steps: list[dict] = []
    discharge_steps: list[dict] = []
    chg_idx = 0
    dchg_idx = 0

    for s in accel_steps:
        # 충전 스텝 추출 (CC 또는 CCCV, Rest 제외)
        if s['chg_mode'] in ('CC', 'CCCV'):
            chg_idx += 1
            if s['chg_mode'] == 'CCCV':
                voltage = s['chg_cv_voltage']
                charge_steps.append({
                    'step': chg_idx,
                    'mode': 'CCCV',
                    'crate': round(s['chg_current_mA'] / capacity, 2) if capacity else 0,
                    'current_mA': round(s['chg_current_mA'], 1),
                    'voltage_cutoff': round(voltage, 3),
                    'current_cutoff_crate': round(s['chg_cutoff_mA'] / capacity, 2) if capacity else 0,
                    'current_cutoff_mA': round(s['chg_cutoff_mA'], 1),
                })
            else:
                voltage = s['chg_cc_endvolt']
                charge_steps.append({
                    'step': chg_idx,
                    'mode': 'CC',
                    'crate': round(s['chg_current_mA'] / capacity, 2) if capacity else 0,
                    'current_mA': round(s['chg_current_mA'], 1),
                    'voltage_cutoff': round(voltage, 3),
                })

        # 방전 스텝 추출 (CC만, Rest 제외)
        if s['dchg_mode'] == 'CC' and s['dchg_current_mA'] > 0:
            dchg_idx += 1
            discharge_steps.append({
                'step': dchg_idx,
                'mode': 'CC',
                'crate': round(s['dchg_current_mA'] / capacity, 2) if capacity else 0,
                'current_mA': round(s['dchg_current_mA'], 1),
                'voltage_cutoff': round(s['dchg_endvolt'], 3),
            })

    if not charge_steps:
        return None

    # 복수 루프 그룹 전압 스케줄 (전압 step-down 패턴 추출)
    voltage_schedule: list[tuple[int, float, int]] = []
    for lg_idx, (lg_s, lg_e, lg_cnt) in enumerate(loop_groups):
        # 해당 루프 그룹 내 충전 최대 CV 전압
        max_chg_v = 0.0
        for s in steps[lg_s:lg_e + 1]:
            if s['chg_mode'] == 'CCCV' and s['chg_cv_voltage'] > max_chg_v:
                max_chg_v = s['chg_cv_voltage']
            elif s['chg_mode'] == 'CC' and s['chg_cc_endvolt'] > max_chg_v:
                max_chg_v = s['chg_cc_endvolt']
        voltage_schedule.append((lg_idx, round(max_chg_v, 3), lg_cnt))

    return {
        'charge_steps': charge_steps,
        'discharge_steps': discharge_steps,
        'n_charge_steps': len(charge_steps),
        'n_discharge_steps': len(discharge_steps),
        'voltage_schedule': voltage_schedule,
    }


def extract_toyo_ptn_structure(
    channel_path: str,
    capacity: float = 0,
) -> dict | None:
    """Toyo .PTN 파일에서 스케줄 구조 정보(시험유형, 패턴) 추출.

    .PTN 파일의 루프/스텝 구조를 분석하여 시험유형을 판별한다.
    toyo_build_cycle_map()에 용량 임계값 힌트를 제공하는 것이 주 용도.

    Parameters
    ----------
    channel_path : str
        Toyo 채널 폴더 경로
    capacity : float
        공칭 용량(mAh). 0이면 Option.PTN에서 추정.

    Returns
    -------
    dict | None
        {
            'schedule_type': str,        # '가속수명'|'GITT'|'율별'|'기타'
            'n_loop_groups': int,        # 루프 그룹 수 (전압 step-down 수)
            'main_loop_count': int,      # 메인 루프 반복 수
            'n_chg_per_loop': int,       # 루프당 충전 스텝 수
            'n_dchg_per_loop': int,      # 루프당 방전 스텝 수
            'has_voltage_stepdown': bool, # 전압 step-down 패턴 존재
            'min_pulse_cap_mAh': float,  # 최소 펄스 용량 추정 (mAh)
        }
    """
    ptn_file = _find_ptn_file(channel_path)
    if not ptn_file:
        return None

    try:
        with open(ptn_file, 'r', encoding='utf-8', errors='replace') as fh:
            lines = fh.readlines()
    except OSError:
        return None
    if len(lines) < 3:
        return None

    # Option 파일에서 용량 읽기
    ptn_cap = _read_ptn_option_capacity(channel_path)
    if ptn_cap > 0:
        capacity = ptn_cap

    # 모든 스텝 파싱
    steps: list[dict] = []
    for line in lines[1:]:
        if len(line) < 100:
            continue
        steps.append(_parse_ptn_step(line))
    if not steps:
        return None

    # 루프 그룹 식별
    loop_groups: list[tuple[int, int, int]] = []
    for i, s in enumerate(steps):
        if s['loop_to'] > 0:
            start = s['loop_to'] - 1
            loop_groups.append((start, i, s['loop_count']))

    n_loop_groups = len(loop_groups)
    main_loop_count = max((lg[2] for lg in loop_groups), default=0)

    # 첫 루프 그룹 내 충전/방전 스텝 수
    n_chg_per_loop = 0
    n_dchg_per_loop = 0
    if loop_groups:
        lg_s, lg_e, _ = loop_groups[0]
        for s in steps[lg_s:lg_e + 1]:
            if s['chg_mode'] in ('CC', 'CCCV'):
                n_chg_per_loop += 1
            if s['dchg_mode'] == 'CC' and s['dchg_current_mA'] > 0:
                n_dchg_per_loop += 1

    # 전압 step-down 감지: 루프 그룹 간 최대 충전 전압이 다르면 True
    voltages: list[float] = []
    for lg_s, lg_e, _ in loop_groups:
        max_v = 0.0
        for s in steps[lg_s:lg_e + 1]:
            if s['chg_mode'] == 'CCCV' and s['chg_cv_voltage'] > max_v:
                max_v = s['chg_cv_voltage']
            elif s['chg_mode'] == 'CC' and s['chg_cc_endvolt'] > max_v:
                max_v = s['chg_cc_endvolt']
        voltages.append(max_v)
    has_stepdown = len(set(round(v, 2) for v in voltages)) > 1

    # 최소 펄스 용량 추정 (방전 전류 × 예상 시간)
    # Toyo 가속수명은 C-rate 기반이므로 capacity × crate × (pulse_time / 60)
    min_pulse_cap = 0.0
    if capacity > 0 and loop_groups:
        lg_s, lg_e, _ = loop_groups[0]
        for s in steps[lg_s:lg_e + 1]:
            if s['dchg_mode'] == 'CC' and s['dchg_current_mA'] > 0:
                # 1C 1h = capacity mAh → 최소 펄스는 용량의 1/60 (1분) 수준으로 추정
                dchg_crate = s['dchg_current_mA'] / capacity if capacity else 0
                # 가속수명: 보통 30min~3h 방전 → min_pulse = capacity × crate × 0.5h
                # 여기선 보수적으로 용량의 5% (3분@1C)
                est = capacity * dchg_crate * (1 / 20)
                if min_pulse_cap == 0 or est < min_pulse_cap:
                    min_pulse_cap = est

    # ── 시험유형 판별 규칙 ──
    # (1) 가속수명: 대형 루프 (20+), 충전 1-2스텝 + 방전 1-2스텝
    if main_loop_count >= 20 and n_chg_per_loop <= 3 and n_dchg_per_loop <= 3:
        schedule_type = '가속수명'
    # (2) GITT: 대형 루프지만 많은 충/방전 스텝 (펄스+휴지 반복)
    elif main_loop_count >= 5 and (n_chg_per_loop >= 5 or n_dchg_per_loop >= 5):
        schedule_type = 'GITT'
    # (3) 율별: 루프 없거나 소수, 다양한 전류의 충방전 나열
    elif main_loop_count <= 5 and n_loop_groups <= 2:
        schedule_type = '율별' if (n_chg_per_loop + n_dchg_per_loop) >= 4 else '기타'
    else:
        schedule_type = '기타'

    return {
        'schedule_type': schedule_type,
        'n_loop_groups': n_loop_groups,
        'main_loop_count': main_loop_count,
        'n_chg_per_loop': n_chg_per_loop,
        'n_dchg_per_loop': n_dchg_per_loop,
        'has_voltage_stepdown': has_stepdown,
        'min_pulse_cap_mAh': round(min_pulse_cap, 2),
    }


def _snap_accel_pattern(pattern: dict) -> dict:
    """패턴 분석 결과의 C-rate/전압을 표준값으로 일괄 스냅."""
    for step in pattern['charge_steps']:
        step['crate'] = _snap_crate(step['crate'])
        step['voltage_cutoff'] = _snap_voltage(step['voltage_cutoff'])
        if 'current_cutoff_crate' in step:
            step['current_cutoff_crate'] = _snap_crate(step['current_cutoff_crate'])
    for step in pattern['discharge_steps']:
        step['crate'] = _snap_crate(step['crate'])
        step['voltage_cutoff'] = _snap_voltage(step['voltage_cutoff'])
    return pattern


def _extract_toyo_step_currents(
    channel_path: str, totl_cycle: int, condition: int,
) -> tuple[float, float]:
    """Toyo 원시 사이클 파일에서 CC 전류(mA)와 CV cutoff 전류(mA) 추출."""
    cycle_file = os.path.join(channel_path, '%06d' % totl_cycle)
    if not os.path.isfile(cycle_file):
        return (0.0, 0.0)
    try:
        raw = pd.read_csv(
            cycle_file, sep=',', skiprows=3,
            encoding='cp949', on_bad_lines='skip',
        )
    except Exception:
        return (0.0, 0.0)

    cur_col = 'Current[mA]'
    cond_col = 'Condition'
    if cur_col not in raw.columns or cond_col not in raw.columns:
        return (0.0, 0.0)

    active = raw[(raw[cond_col] == condition) & (raw[cur_col].abs() > 0)]
    if active.empty:
        return (0.0, 0.0)

    currents = active[cur_col].abs().values
    # CC 전류: 최대 전류의 95% 이상인 값의 중앙값 (CC 플래토 추출)
    max_cur = currents.max()
    cc_plateau = currents[currents >= max_cur * 0.95]
    cc_current = float(np.median(cc_plateau)) if len(cc_plateau) > 0 else float(max_cur)
    # CV cutoff 전류: 마지막 전류
    cv_cutoff = float(currents[-1])
    return (cc_current, cv_cutoff)


def _analyze_accel_pattern_toyo(
    channel_path: str, capacity: float,
    raw_df: pd.DataFrame | None = None,
) -> dict | None:
    """Toyo capacity.log 기반 가속수명 충방전 패턴 분석.

    첫 번째 가속수명 사이클의 충전/방전 스텝별
    C-rate, CC/CCCV 모드, voltage/current cutoff 정보를 추출한다.
    """
    # 이미 로딩된 DataFrame 재사용 (없으면 파일 로딩)
    if raw_df is not None:
        df = raw_df.copy()
    else:
        cap_log_path = os.path.join(channel_path, 'capacity.log')
        if not os.path.isfile(cap_log_path):
            for f in os.listdir(channel_path):
                if f.upper() == 'CAPACITY.LOG':
                    cap_log_path = os.path.join(channel_path, f)
                    break
            else:
                return None

        try:
            df = pd.read_csv(
                cap_log_path, sep=',', encoding='cp949', on_bad_lines='skip',
            )
        except Exception:
            return None

    # 컬럼명 통일
    col_map = {
        'Total Cycle': 'TotlCycle', 'Capacity[mAh]': 'Cap[mAh]',
        'End Factor': 'Finish', 'Peak Volt.[V]': 'PeakVolt[V]',
    }
    df.rename(columns={k: v for k, v in col_map.items() if k in df.columns},
              inplace=True)
    for need in ('Condition', 'TotlCycle', 'Finish', 'PeakVolt[V]', 'Cap[mAh]'):
        if need not in df.columns:
            return None

    conds = df['Condition'].values

    # 첫 번째 가속수명 구간 탐색 (연속 Condition==1 행 2개 이상)
    i = 0
    chg_start = chg_end = dchg_start = dchg_end = None
    while i < len(df):
        start = i
        cond = int(conds[i])
        while i < len(df) and int(conds[i]) == cond:
            i += 1
        if cond == 1 and (i - start) >= 2 and chg_start is None:
            chg_start, chg_end = start, i
            # 직후 방전 그룹도 포함
            if i < len(df) and int(conds[i]) == 2:
                dchg_start = i
                while i < len(df) and int(conds[i]) == 2:
                    i += 1
                dchg_end = i
            break
    if chg_start is None:
        return None

    # 충전 스텝 분석
    charge_steps = []
    for idx, row_idx in enumerate(range(chg_start, chg_end)):
        row = df.iloc[row_idx]
        tc = int(row['TotlCycle'])
        finish = str(row['Finish']).strip()
        peak_v = float(row['PeakVolt[V]'])
        step_cap = float(row['Cap[mAh]'])
        cc_cur, cv_cut = _extract_toyo_step_currents(channel_path, tc, 1)

        if finish in ('Cur', 'Cur.'):
            # CCCV: CC 충전 → 전압 도달 후 CV → 전류 cutoff
            charge_steps.append({
                'step': idx + 1,
                'mode': 'CCCV',
                'crate': round(cc_cur / capacity, 2) if capacity else 0,
                'current_mA': round(cc_cur, 1),
                'voltage_cutoff': round(peak_v, 3),
                'current_cutoff_crate': round(cv_cut / capacity, 2) if capacity else 0,
                'current_cutoff_mA': round(cv_cut, 1),
                'capacity_mAh': round(step_cap, 1),
            })
        else:
            # CC: 정전류 충전 → 전압 도달 시 종료
            charge_steps.append({
                'step': idx + 1,
                'mode': 'CC',
                'crate': round(cc_cur / capacity, 2) if capacity else 0,
                'current_mA': round(cc_cur, 1),
                'voltage_cutoff': round(peak_v, 3),
                'capacity_mAh': round(step_cap, 1),
            })

    # 방전 스텝 분석
    discharge_steps = []
    if dchg_start is not None and dchg_end is not None:
        for idx, row_idx in enumerate(range(dchg_start, dchg_end)):
            row = df.iloc[row_idx]
            tc = int(row['TotlCycle'])
            peak_v = float(row['PeakVolt[V]'])
            step_cap = float(row['Cap[mAh]'])
            cc_cur, _ = _extract_toyo_step_currents(channel_path, tc, 2)

            # 방전 전압 cutoff: 원시 파일의 최저 전압
            cycle_file = os.path.join(channel_path, '%06d' % tc)
            min_v = peak_v
            if os.path.isfile(cycle_file):
                try:
                    raw = pd.read_csv(
                        cycle_file, sep=',', skiprows=3,
                        encoding='cp949', on_bad_lines='skip',
                    )
                    part = raw[raw['Condition'] == 2]
                    if not part.empty:
                        min_v = float(part['Voltage[V]'].min())
                except Exception:
                    pass

            discharge_steps.append({
                'step': idx + 1,
                'mode': 'CC',
                'crate': round(cc_cur / capacity, 2) if capacity else 0,
                'current_mA': round(cc_cur, 1),
                'voltage_cutoff': round(min_v, 3),
                'capacity_mAh': round(step_cap, 1),
            })

    return {
        'charge_steps': charge_steps,
        'discharge_steps': discharge_steps,
        'n_charge_steps': len(charge_steps),
        'n_discharge_steps': len(discharge_steps),
    }


def _analyze_accel_pattern_pne(
    channel_path: str, capacity: float,
    raw_df: pd.DataFrame | None = None,
) -> dict | None:
    """PNE SaveEndData 기반 가속수명 충방전 패턴 분석.

    PNE SaveEndData 주요 컬럼 인덱스:
      [2]  StepType  1=Chg, 2=Dchg, 3=Rest, 8=Loop
      [6]  EndState  65=전압종료(CC), 66=전류종료(CCCV)
      [8]  EndVoltage (μV)
      [9]  EndCurrent (μA, 충전=양수, 방전=음수)
      [27] TotlCycle
      [32] CV구간 시간 (centisec)
      [38] CC구간 시간 (centisec)
      [39] CC구간 용량 (μAh)
      [40] CV구간 용량 (μAh)
    """
    # 이미 로딩된 DataFrame 재사용 (없으면 캐시에서 로딩)
    if raw_df is not None:
        df = raw_df
    else:
        df, _, _ = _cached_pne_restore_files(channel_path)
        if df is None:
            return None
    if df.shape[1] < 41:
        return None

    # 가속수명 사이클 찾기: 최빈 (n_chg, n_dchg) 패턴 기반
    # — 단순 "첫 n_chg>=2" 방식은 RPT(0.2C 다단계)를 오인하는 문제 있음
    real = df[df[2] != 8]
    from collections import Counter as _Counter
    _cyc_pats = []  # [(TotlCycle, n_chg, n_dchg)]
    for cyc, group in real.groupby(27):
        n_chg = (group[2] == 1).sum()
        n_dchg = (group[2] == 2).sum()
        if n_chg >= 2 and n_dchg >= 1:
            _cyc_pats.append((cyc, int(n_chg), int(n_dchg)))
    if not _cyc_pats:
        return None
    _pat_cnt = _Counter((nc, nd) for _, nc, nd in _cyc_pats)
    _mode_pat = _pat_cnt.most_common(1)[0][0]
    first_accel_cyc = None
    for cyc, nc, nd in _cyc_pats:
        if (nc, nd) == _mode_pat:
            first_accel_cyc = cyc
            break
    if first_accel_cyc is None:
        return None

    cyc_data = real[real[27] == first_accel_cyc]

    # 충전 스텝 분석
    charge_steps = []
    chg_rows = cyc_data[cyc_data[2] == 1]
    for idx, (_, row) in enumerate(chg_rows.iterrows()):
        end_state = int(row[6])
        end_v = row[8] / 1e6        # μV → V
        end_cur = row[9] / 1000     # μA → mA
        cc_time = row[38] / 100     # centisec → sec
        cv_time = row[32] / 100
        cc_cap = row[39] / 1000     # μAh → mAh
        cv_cap = row[40] / 1000

        if end_state == 66 and cc_time > 0:
            # CCCV: CC 전류를 용량/시간으로 계산
            cc_cur = cc_cap / (cc_time / 3600)  # mA
            cutoff_cur = abs(end_cur)            # mA
            charge_steps.append({
                'step': idx + 1,
                'mode': 'CCCV',
                'crate': round(cc_cur / capacity, 2) if capacity else 0,
                'current_mA': round(cc_cur, 1),
                'voltage_cutoff': round(end_v, 3),
                'current_cutoff_crate': round(cutoff_cur / capacity, 2) if capacity else 0,
                'current_cutoff_mA': round(cutoff_cur, 1),
                'capacity_mAh': round(cc_cap + cv_cap, 1),
            })
        else:
            # CC: 종료 전류 = CC 전류
            charge_steps.append({
                'step': idx + 1,
                'mode': 'CC',
                'crate': round(abs(end_cur) / capacity, 2) if capacity else 0,
                'current_mA': round(abs(end_cur), 1),
                'voltage_cutoff': round(end_v, 3),
                'capacity_mAh': round(cc_cap, 1),
            })

    # 방전 스텝 분석
    discharge_steps = []
    dchg_rows = cyc_data[cyc_data[2] == 2]
    for idx, (_, row) in enumerate(dchg_rows.iterrows()):
        end_v = row[8] / 1e6
        end_cur = abs(row[9] / 1000)  # mA (절대값)
        dchg_cap = row[11] / 1000

        discharge_steps.append({
            'step': idx + 1,
            'mode': 'CC',
            'crate': round(end_cur / capacity, 2) if capacity else 0,
            'current_mA': round(end_cur, 1),
            'voltage_cutoff': round(end_v, 3),
            'capacity_mAh': round(dchg_cap, 1),
        })

    return {
        'charge_steps': charge_steps,
        'discharge_steps': discharge_steps,
        'n_charge_steps': len(charge_steps),
        'n_discharge_steps': len(discharge_steps),
    }


def analyze_accel_pattern(
    channel_path: str, capacity: float,
    classified: list[dict], is_pne: bool,
    raw_df: pd.DataFrame | None = None,
) -> dict | None:
    """가속수명 사이클의 충방전 패턴(스텝 수, C-rate, cutoff) 분석.

    Parameters
    ----------
    channel_path : str
        채널 폴더 경로
    capacity : float
        공칭 용량(mAh)
    classified : list[dict]
        classify_*_cycles 결과
    is_pne : bool
        PNE 여부
    raw_df : pd.DataFrame | None
        이미 로딩한 원본 CSV (재사용하여 파일 재로딩 방지)

    Returns
    -------
    dict | None
        {
            'charge_steps': [{'step', 'mode', 'crate', ...}, ...],
            'discharge_steps': [...],
            'n_charge_steps': int,
            'n_discharge_steps': int,
        }
    """
    accel_exists = any(c.get('category') == '가속수명' for c in classified)
    if not accel_exists:
        return None
    if is_pne:
        # .sch 우선 → CSV 폴백 전략
        result = None
        if HAS_SCH_PARSER:
            sch_file = _find_sch_file(channel_path)
            if sch_file:
                result = extract_accel_pattern_from_sch(sch_file, capacity)
        if result is None:
            result = _analyze_accel_pattern_pne(channel_path, capacity, raw_df=raw_df)
    else:
        # PTN 파서 우선 → capacity.log 폴백
        result = _parse_toyo_ptn(channel_path, capacity)
        if result is None:
            result = _analyze_accel_pattern_toyo(channel_path, capacity, raw_df=raw_df)
    # C-rate / 전압 표준값 스냅 (충방전기 미세 오차 보정)
    if result:
        result = _snap_accel_pattern(result)
    return result


def _fmt_crate(val: float) -> str:
    """C-rate 표시: 정수면 '2.0C', 아니면 소수점 적절히."""
    if val == int(val):
        return f'{val:.1f}'
    # 0.05 단위 → 소수점 2자리까지
    return f'{val:.2f}'


# ═══════════════════════════════════════════════════════════════
# PNE .sch 바이너리 파서 (내장)
# ═══════════════════════════════════════════════════════════════

# .sch 타입 코드 → 문자열 매핑
_SCH_TYPE_MAP: dict[int, str] = {
    0x0101: 'CHG_CC',
    0x0201: 'CHG_CCCV',
    0x0202: 'DCHG_CC',
    0xFF03: 'REST',
    0xFF06: 'GOTO',
    0xFF07: 'REST_SAFE',
    0xFF08: 'LOOP',
}

_SCH_BLOCK_SIZE = 652       # 스텝 블록 크기 (bytes)
_SCH_HEADER_SIZE = 1920     # 파일 헤더 크기 (bytes)


def _parse_pne_sch(sch_path: str) -> dict | None:
    """PNE .sch 바이너리 파일을 파싱하여 스텝 구조 반환.

    Parameters
    ----------
    sch_path : str
        .sch 파일 절대 경로.

    Returns
    -------
    dict | None
        {
            'steps': list[dict],           # 전체 스텝 (순서대로)
            'loop_steps': list[dict],      # LOOP 스텝만 (loop_count 포함)
            'charge_steps': list[dict],    # CHG_CC, CHG_CCCV 스텝
            'discharge_steps': list[dict], # DCHG_CC 스텝
        }
        파싱 실패 시 None.

    Notes
    -----
    .sch 구조:
      - 헤더: 1920 bytes (magic + schedule 메타데이터)
      - 스텝 블록: 각 652 bytes 고정
        +0: step_number (uint32)
        +8: type_code (uint32)
        +12/+16: voltage (mV, uint32) — CHG는 +12, DCHG는 +16
        +20: current (mA, uint32)
        +24: time_limit (sec, uint32)
        +28: cv_voltage (mV, CHG_CCCV 전용)
        +32: cv_cutoff_current (mA, CHG_CCCV 전용)
        +56: loop_count (uint32, LOOP 전용)
        +104: capacity_limit (mAh, uint32)
        +336: record_interval (sec, uint32)
        +372: end_condition_value_pct (float32)
        +500: end_condition_type (uint32)
        +504: end_condition_enabled (uint32)
    """
    try:
        with open(sch_path, 'rb') as f:
            data = f.read()
    except (OSError, IOError):
        return None

    if len(data) < _SCH_HEADER_SIZE + _SCH_BLOCK_SIZE:
        return None

    # 매직 넘버 검증 (선택적 — 첫 4바이트)
    # PNE .sch magic = (740721, ...)
    magic = struct.unpack_from('<I', data, 0)[0]
    if magic != 740721:
        return None

    n_steps = (len(data) - _SCH_HEADER_SIZE) // _SCH_BLOCK_SIZE
    if n_steps <= 0:
        return None

    steps = []
    loop_steps = []
    charge_steps = []
    discharge_steps = []

    for i in range(n_steps):
        offset = _SCH_HEADER_SIZE + i * _SCH_BLOCK_SIZE
        if offset + _SCH_BLOCK_SIZE > len(data):
            break

        blk = data[offset:offset + _SCH_BLOCK_SIZE]
        step_num = struct.unpack_from('<I', blk, 0)[0]
        type_code = struct.unpack_from('<I', blk, 8)[0]
        type_name = _SCH_TYPE_MAP.get(type_code, f'UNKNOWN_0x{type_code:04X}')

        step_info: dict = {
            'step': step_num,
            'type': type_name,
            'type_code': type_code,
        }

        if type_name in ('CHG_CC', 'CHG_CCCV'):
            # 충전 스텝 공통 필드
            voltage_mV = struct.unpack_from('<I', blk, 12)[0]
            current_mA = struct.unpack_from('<I', blk, 20)[0]
            time_limit = struct.unpack_from('<I', blk, 24)[0]
            cap_limit = struct.unpack_from('<I', blk, 104)[0]
            step_info.update({
                'voltage_mV': voltage_mV,
                'current_mA': current_mA,
                'time_limit_s': time_limit,
                'capacity_limit_mAh': cap_limit,
            })
            if type_name == 'CHG_CCCV':
                cv_voltage = struct.unpack_from('<I', blk, 28)[0]
                cv_cutoff = struct.unpack_from('<I', blk, 32)[0]
                step_info['cv_voltage_mV'] = cv_voltage
                step_info['cv_cutoff_mA'] = cv_cutoff
            charge_steps.append(step_info)

        elif type_name == 'DCHG_CC':
            # 방전 스텝: 전압 오프셋이 +16 (CHG와 다름)
            voltage_mV = struct.unpack_from('<I', blk, 16)[0]
            current_mA = struct.unpack_from('<I', blk, 20)[0]
            time_limit = struct.unpack_from('<I', blk, 24)[0]
            cap_limit = struct.unpack_from('<I', blk, 104)[0]
            step_info.update({
                'voltage_mV': voltage_mV,
                'current_mA': current_mA,
                'time_limit_s': time_limit,
                'capacity_limit_mAh': cap_limit,
            })
            discharge_steps.append(step_info)

        elif type_name == 'LOOP':
            loop_count = struct.unpack_from('<I', blk, 56)[0]
            step_info['loop_count'] = loop_count
            loop_steps.append(step_info)

        elif type_name in ('REST', 'REST_SAFE'):
            time_limit = struct.unpack_from('<I', blk, 24)[0]
            step_info['time_limit_s'] = time_limit

        elif type_name == 'GOTO':
            # GOTO 대상 스텝: +56 offset (LOOP와 같은 위치)
            goto_target = struct.unpack_from('<I', blk, 56)[0]
            step_info['goto_target'] = goto_target

        # End Condition (SOC/DOD 종료 조건) — Rss 판별용
        ec_type = struct.unpack_from('<I', blk, 500)[0]
        ec_enabled = struct.unpack_from('<I', blk, 504)[0]
        if ec_type != 0 and ec_enabled == 1:
            ec_value = struct.unpack_from('<f', blk, 372)[0]
            step_info['end_condition'] = {
                'type': ec_type,
                'value_pct': round(ec_value, 2),
            }

        steps.append(step_info)

    if not steps:
        return None

    return {
        'steps': steps,
        'loop_steps': loop_steps,
        'charge_steps': charge_steps,
        'discharge_steps': discharge_steps,
    }


def extract_accel_pattern_from_sch(
    sch_path: str,
    capacity: float = 0,
) -> dict | None:
    """PNE .sch 파일에서 가속수명 충방전 패턴 추출.

    _analyze_accel_pattern_pne() 호환 형식의 dict를 반환한다.
    .sch 바이너리에서 직접 스텝 구조를 읽으므로 SaveEndData CSV 대비 65배+ 빠름.

    Parameters
    ----------
    sch_path : str
        .sch 파일 경로.
    capacity : float
        공칭 용량(mAh). 0이면 C-rate = 0으로 표시.

    Returns
    -------
    dict | None
        {
            'charge_steps': [{'step', 'mode', 'crate', 'current_mA',
                              'voltage_cutoff', ...}, ...],
            'discharge_steps': [...],
            'n_charge_steps': int,
            'n_discharge_steps': int,
        }
    """
    parsed = _parse_pne_sch(sch_path)
    if not parsed:
        return None

    # 메인 루프 내 스텝만 사용 (가속수명 = 대형 루프 내부 패턴)
    # 루프를 찾고, 그 직전 스텝들이 실제 충방전 패턴
    loop_steps = parsed.get('loop_steps', [])
    all_steps = parsed['steps']

    # 대형 루프 (count >= 20) 찾기
    main_loop = None
    main_loop_idx = None
    for idx, s in enumerate(all_steps):
        if s['type'] == 'LOOP' and s.get('loop_count', 0) >= 20:
            main_loop = s
            main_loop_idx = idx
            break

    if main_loop is None:
        return None

    # 메인 루프 직전의 1사이클 패턴 블록만 추출 (역방향 phase 탐색)
    # 가속수명 스케줄: [화성 + LOOP] [RPT] [메인 CHG+REST+DCHG+REST] [LOOP 50+]
    # 역방향 phase: REST(skip) → DCHG 블록 → REST(skip) → CHG 블록 → 종료
    chg_steps = []
    dchg_steps = []
    phase = 'seek_dchg'  # 역방향: DCHG 먼저 찾기
    for idx in range(main_loop_idx - 1, -1, -1):
        s = all_steps[idx]
        t = s['type']
        if t in ('LOOP', 'GOTO'):
            break  # 이전 제어 스텝 도달 → 패턴 경계
        if phase == 'seek_dchg':
            if t == 'DCHG_CC':
                dchg_steps.insert(0, s)
                phase = 'in_dchg'
            # REST는 스킵
        elif phase == 'in_dchg':
            if t == 'DCHG_CC':
                dchg_steps.insert(0, s)
            elif t in ('REST', 'REST_SAFE'):
                phase = 'seek_chg'  # DCHG 블록 끝 → CHG 탐색
            elif t in ('CHG_CC', 'CHG_CCCV'):
                # DCHG 직전에 CHG가 바로 오는 경우 (REST 없이)
                chg_steps.insert(0, s)
                phase = 'in_chg'
        elif phase == 'seek_chg':
            if t in ('CHG_CC', 'CHG_CCCV'):
                chg_steps.insert(0, s)
                phase = 'in_chg'
            elif t == 'DCHG_CC':
                break  # 이전 사이클의 DCHG → 패턴 경계
        elif phase == 'in_chg':
            if t in ('CHG_CC', 'CHG_CCCV'):
                chg_steps.insert(0, s)
            else:
                break  # CHG 블록 종료 → 1사이클 패턴 완성

    if not chg_steps and not dchg_steps:
        return None

    # 반환 형식: _analyze_accel_pattern_pne() 호환
    charge_result = []
    for idx, s in enumerate(chg_steps):
        cur_mA = s.get('current_mA', 0)
        v_cutoff = s.get('voltage_mV', 0) / 1000  # mV → V
        entry: dict = {
            'step': idx + 1,
            'mode': 'CCCV' if s['type'] == 'CHG_CCCV' else 'CC',
            'crate': round(cur_mA / capacity, 2) if capacity else 0,
            'current_mA': cur_mA,
            'voltage_cutoff': round(v_cutoff, 3),
        }
        if s['type'] == 'CHG_CCCV' and 'cv_cutoff_mA' in s:
            entry['current_cutoff_crate'] = (
                round(s['cv_cutoff_mA'] / capacity, 2) if capacity else 0
            )
            entry['current_cutoff_mA'] = s['cv_cutoff_mA']
        charge_result.append(entry)

    discharge_result = []
    for idx, s in enumerate(dchg_steps):
        cur_mA = s.get('current_mA', 0)
        v_cutoff = s.get('voltage_mV', 0) / 1000  # mV → V
        discharge_result.append({
            'step': idx + 1,
            'mode': 'CC',
            'crate': round(cur_mA / capacity, 2) if capacity else 0,
            'current_mA': cur_mA,
            'voltage_cutoff': round(v_cutoff, 3),
        })

    return {
        'charge_steps': charge_result,
        'discharge_steps': discharge_result,
        'n_charge_steps': len(charge_result),
        'n_discharge_steps': len(discharge_result),
    }


_ORDINALS = ['1st', '2nd', '3rd'] + [f'{i}th' for i in range(4, 21)]


def _ordinal(n: int) -> str:
    """1-based 인덱스 → 서수 문자열 (1st, 2nd, 3rd, 4th ...)."""
    if 1 <= n <= len(_ORDINALS):
        return _ORDINALS[n - 1]
    return f'{n}th'


def extract_schedule_structure_from_sch(
    sch_path: str,
    capacity: float = 0,
) -> dict | None:
    """PNE .sch 파일에서 스케줄 구조 정보(시험유형, 패턴) 추출.

    .sch 파일의 스텝/루프 구조를 분석하여 시험유형을 판별한다.
    pne_build_cycle_map()에 sweep_mode 힌트를 제공하는 것이 주 용도.

    Parameters
    ----------
    sch_path : str
        .sch 파일 경로
    capacity : float
        공칭 용량(mAh). 0이면 .sch 내부에서 추정.

    Returns
    -------
    dict | None
        {
            'schedule_type': str,     # '가속수명'|'GITT'|'Rss'|'SOC별DCIR'|'율별'|'기타'
            'pattern_string': str,    # 스텝 시퀀스 요약
            'has_rss': bool,          # Rss(DCIR) 섹션 포함 여부
            'has_gitt_hppc': bool,    # GITT/HPPC 펄스 루프 포함 여부
            'sweep_mode': bool|None,  # True=스윕강제, False=일반강제, None=미결정
        }
    """
    if not HAS_SCH_PARSER:
        return None
    try:
        parsed = _parse_pne_sch(sch_path)
    except Exception:
        return None
    if not parsed:
        return None

    steps = parsed['steps']
    loop_steps = parsed.get('loop_steps', [])
    charge_steps = parsed.get('charge_steps', [])
    discharge_steps = parsed.get('discharge_steps', [])
    n_steps = len(steps)

    # 루프 분석: count > 1인 실질 반복 루프만 추출
    real_loops = [s for s in loop_steps if s.get('loop_count', 0) > 1]
    max_loop = max((s.get('loop_count', 0) for s in real_loops), default=0)
    n_real_loops = len(real_loops)
    unique_loop_counts = set(s.get('loop_count', 0) for s in real_loops)

    # 스텝 타입 시퀀스에서 CHG/DCHG 비율
    n_chg = len(charge_steps)
    n_dchg = len(discharge_steps)

    # 패턴 문자열 생성 (스텝 타입 RLE)
    type_seq = [s['type'] for s in steps]
    rle_parts = []
    if type_seq:
        cur, cnt = type_seq[0], 1
        for t in type_seq[1:]:
            if t == cur:
                cnt += 1
            else:
                rle_parts.append(f'{cur}×{cnt}' if cnt > 1 else cur)
                cur, cnt = t, 1
        rle_parts.append(f'{cur}×{cnt}' if cnt > 1 else cur)
    pattern_string = ' → '.join(rle_parts[:20])
    if len(rle_parts) > 20:
        pattern_string += ' → ...'

    # ── 시험유형 판별 규칙 ──
    # (1) GITT: 소수 스텝에 대형 루프 (단방향 펄스 반복)
    #     예: 17 steps, LOOP 105회 — 펄스+REST 반복
    if max_loop >= 20 and n_steps <= 30:
        schedule_type = 'GITT'
        has_gitt_hppc = True
        has_rss = False
        sweep_mode = True

    # (2) SOC별DCIR: 다수 독립 루프 그룹 (SOC 포인트별 펄스)
    #     예: 105 steps, 6+ 루프, 각기 다른 count (5~25)
    elif n_real_loops >= 4 and len(unique_loop_counts) >= 3:
        schedule_type = 'SOC별DCIR'
        has_gitt_hppc = True
        has_rss = False
        sweep_mode = True

    # (3) 가속수명 / Rss: 대형 루프 (30+) + 다수 스텝 (50+)
    #     예: 204/215 steps, main loop 47~97회
    elif max_loop >= 20 and n_steps >= 50:
        schedule_type = '가속수명'
        has_rss = n_steps >= 100  # Rss 포함 스케줄은 보통 100+ 스텝
        has_gitt_hppc = False
        sweep_mode = False

    # (4) 율별: 대형 루프 없음, 다수 단독 CHG/DCHG 스텝 (각기 다른 전류)
    elif max_loop <= 5 and n_chg + n_dchg >= 6:
        schedule_type = '율별'
        has_rss = False
        has_gitt_hppc = False
        sweep_mode = False  # 율별은 각 rate가 풀 사이클

    # (5) 미결정: .sch 구조가 위 패턴에 해당하지 않음 → 데이터 휴리스틱에 위임
    else:
        schedule_type = '기타'
        has_rss = False
        has_gitt_hppc = False
        sweep_mode = None  # 데이터 휴리스틱 폴백

    return {
        'schedule_type': schedule_type,
        'pattern_string': pattern_string,
        'has_rss': has_rss,
        'has_gitt_hppc': has_gitt_hppc,
        'sweep_mode': sweep_mode,
    }


@functools.lru_cache(maxsize=128)
def _find_sch_file(channel_path: str) -> str | None:
    """채널 폴더에서 .sch 파일 경로를 반환. 없으면 None.

    동일 스케줄에 _000, _001 등 채널별 사본이 있으면
    접미사 번호가 가장 큰 파일(=최신 패턴)을 선택한다.
    lru_cache: 같은 경로 중복 탐색 방지 (classify + analyze_accel 2회 호출).
    """
    _SCH_SUFFIX_RE = re.compile(r'^(.+?)(?:_(\d{3}))\.sch$', re.IGNORECASE)
    try:
        sch_files = [f for f in os.listdir(channel_path) if f.lower().endswith('.sch')]
    except OSError:
        return None
    if not sch_files:
        return None
    if len(sch_files) == 1:
        return os.path.join(channel_path, sch_files[0])
    # 접미사 번호 기준 정렬 → 가장 큰 번호 우선, 접미사 없는 원본은 -1
    def _sort_key(name):
        m = _SCH_SUFFIX_RE.match(name)
        return int(m.group(2)) if m else -1
    sch_files.sort(key=_sort_key, reverse=True)
    return os.path.join(channel_path, sch_files[0])


@functools.lru_cache(maxsize=256)
def _get_pne_sch_struct(channel_path: str, mincapacity: float) -> dict | None:
    """채널 경로에서 .sch 파일을 찾아 스케줄 구조 정보를 캐시로 반환.

    _find_sch_file + extract_schedule_structure_from_sch 를 1회만 수행하고
    결과를 캐시한다. 프로필/사이클/분류 파이프라인에서 공유.

    Parameters
    ----------
    channel_path : str
        PNE 채널 폴더 경로.
    mincapacity : float
        공칭 용량 (mAh).

    Returns
    -------
    dict | None
        extract_schedule_structure_from_sch() 반환값.
    """
    sch_file = _find_sch_file(channel_path)
    if not sch_file:
        return None
    try:
        return extract_schedule_structure_from_sch(sch_file, mincapacity)
    except Exception:
        return None


@functools.lru_cache(maxsize=256)
def _get_pne_cycle_map(
    channel_path: str, mincapacity: float, ini_crate: float,
) -> tuple[dict, float]:
    """pne_build_cycle_map 캐시 래퍼.

    동일 (채널경로, 공칭용량, 초기C-rate) 조합에 대해 cycle_map을
    1회만 계산하고 이후 캐시 반환. 사이클/프로필/UI 파이프라인에서 공유.
    _get_pne_sch_struct 캐시와 연동하여 .sch 파싱도 재사용.

    Parameters
    ----------
    channel_path : str
        PNE 채널 폴더 경로.
    mincapacity : float
        공칭 용량 (mAh). 사전에 pne_min_cap()으로 해결 필요.
    ini_crate : float
        초기 C-rate.

    Returns
    -------
    tuple[dict, float]
        (cycle_map, mincapacity).
    """
    _sch_struct = _get_pne_sch_struct(channel_path, mincapacity)
    return pne_build_cycle_map(
        channel_path, mincapacity, ini_crate, sch_struct=_sch_struct,
    )


def _fmt_step(s: dict) -> str:
    """단일 스텝 → '[Nth] MODE C-rate/Voltage(/cutoff)' 포맷 문자열."""
    ord_str = _ordinal(s['step'])
    cr = _fmt_crate(s['crate'])
    vcut = f'{s["voltage_cutoff"]:.2f}'
    if s['mode'] == 'CCCV':
        if 'current_cutoff_crate' in s:
            icut = _fmt_crate(s['current_cutoff_crate'])
            return f'[{ord_str}] CCCV {cr}C/{vcut}V/{icut}C cutoff'
        return f'[{ord_str}] CCCV {cr}C/{vcut}V'
    return f'[{ord_str}] CC {cr}C/{vcut}V'


def format_accel_pattern(pattern: dict) -> list[str]:
    """가속수명 패턴을 콘솔 로그용 문자열 목록으로 반환."""
    chg = ' → '.join(_fmt_step(s) for s in pattern['charge_steps'])
    dchg = ' → '.join(_fmt_step(s) for s in pattern['discharge_steps'])
    return [
        f'    ▷ 충전 {pattern["n_charge_steps"]}step: {chg}'
        f' | 방전 {pattern["n_discharge_steps"]}step: {dchg}',
    ]


def _pattern_signature(pattern: dict) -> str:
    """패턴 딕셔너리의 고유 서명 문자열 (그룹 간 중복 비교용)."""
    chg = ' → '.join(_fmt_step(s) for s in pattern['charge_steps'])
    dchg = ' → '.join(_fmt_step(s) for s in pattern['discharge_steps'])
    return f'{chg}|{dchg}'


def toyo_step_Profile_batch(raw_file_path, cycle_list, mincapacity, cutoff, inirate):
    """
    Toyo 스텝 프로파일 배치 로딩: 채널당 1회 min_cap 산정 후, 사이클 반복.
    """
    
    mincapacity = toyo_min_cap(raw_file_path, mincapacity, inirate)
    results = {}
    for inicycle in cycle_list:
        df = pd.DataFrame()
        if os.path.isfile(raw_file_path + "\\%06d" % inicycle):
            tempdata = toyo_Profile_import(raw_file_path, inicycle)
            stepcyc = inicycle
            lasttime = 0
            if int(tempdata.dataraw["Condition"].max()) < 2:
                df.stepchg = tempdata.dataraw
                df.stepchg = df.stepchg[(df.stepchg["Condition"] == 1)]
                lasttime = df.stepchg["PassTime[Sec]"].max()
                _frames = [df.stepchg]
                maxcon = 1
                while maxcon == 1:
                    stepcyc = stepcyc + 1
                    tempdata = toyo_Profile_import(raw_file_path, stepcyc)
                    maxcon = int(tempdata.dataraw["Condition"].max())
                    tempdata.dataraw = tempdata.dataraw[(tempdata.dataraw["Condition"] == 1)]
                    tempdata.dataraw["PassTime[Sec]"] = tempdata.dataraw["PassTime[Sec]"] + lasttime
                    _frames.append(tempdata.dataraw)
                    if not tempdata.dataraw.empty:
                        lasttime = tempdata.dataraw["PassTime[Sec]"].max()
                df.stepchg = pd.concat(_frames)
            else:
                df.stepchg = tempdata.dataraw
                df.stepchg = df.stepchg[(df.stepchg["Condition"] == 1)]
            if not df.stepchg.empty:
                df.stepchg["Cap[mAh]"] = 0
                df.stepchg = df.stepchg[df.stepchg["Current[mA]"] >= (cutoff * mincapacity)]
                df.stepchg = df.stepchg.reset_index()
                initial_cap = df.stepchg["Cap[mAh]"].iloc[0]
                df.stepchg["delta_time"] = (
                    df.stepchg["PassTime[Sec]"].shift(-1) - df.stepchg["PassTime[Sec]"]
                )
                df.stepchg["next_current"] = df.stepchg["Current[mA]"].shift(-1)
                df.stepchg["contribution"] = (df.stepchg["delta_time"] * df.stepchg["next_current"]) / 3600
                df.stepchg["Cap[mAh]"] = initial_cap + df.stepchg["contribution"].fillna(0).cumsum().shift(1, fill_value=0)
                df.stepchg.drop(["delta_time", "next_current", "contribution"], axis=1, inplace=True)
                df.stepchg["PassTime[Sec]"] = df.stepchg["PassTime[Sec]"]/60
                df.stepchg["Current[mA]"] = df.stepchg["Current[mA]"]/mincapacity
                df.stepchg["Cap[mAh]"] = df.stepchg["Cap[mAh]"]/mincapacity
                df.stepchg = df.stepchg[["PassTime[Sec]", "Cap[mAh]", "Voltage[V]", "Current[mA]", "Temp1[Deg]"]]
                df.stepchg.columns = ["TimeMin", "SOC", "Vol", "Crate", "Temp"]
        results[inicycle] = [mincapacity, df]
    return results


def pne_step_Profile_batch(raw_file_path, cycle_list, mincapacity, cutoff, inirate):
    """
    PNE 프로파일: 인덱스 파일/원시 데이터를 1회 loading 후, 메모리에서 사이클별 데이터 분배.
    """
    mincapacity, all_raw, is_pne21_22 = _pne_load_profile_raw(
        raw_file_path, min(cycle_list), max(cycle_list) + 1, mincapacity, inirate)
    results = {}
    if all_raw is None:
        for cyc in cycle_list:
            results[cyc] = [mincapacity, pd.DataFrame()]
        return results
    
    # 사이클별 데이터 분배 (메모리에서)
    for inicycle in cycle_list:
        df = pd.DataFrame()
        cycle_raw = all_raw[(all_raw[27] == inicycle) & (all_raw[2].isin([9, 1]))]
        if len(cycle_raw) > 0:
            cycle_raw = cycle_raw[[17, 8, 9, 21, 10, 7]].copy()
            cycle_raw.columns = ["PassTime[Sec]", "Voltage[V]", "Current[mA]", "Temp1[Deg]", "Chgcap", "step"]
            _pne_normalize_profile(cycle_raw, mincapacity, raw_file_path, cap_col="Chgcap")
            df.stepchg = _merge_step_profiles(cycle_raw, cap_col="Chgcap")
            # cut-off 및 컬럼 정리
            if hasattr(df, "stepchg"):
                df.stepchg = df.stepchg[(df.stepchg["Current[mA]"] >= cutoff)]
                df.stepchg = df.stepchg[["PassTime[Sec]", "Chgcap", "Voltage[V]", "Current[mA]", "Temp1[Deg]"]]
                df.stepchg.columns = ["TimeMin", "SOC", "Vol", "Crate", "Temp"]
        results[inicycle] = [mincapacity, df]
    return results


# PNE SaveData 로딩
def _pne_load_profile_raw(raw_file_path, min_cycle, max_cycle, mincapacity, inirate):
    """PNE SaveData 파일을 일괄 로딩하는 배치 공통 헬퍼.
    min_cycle ~ max_cycle 범위의 원시 데이터를 1회 디스크 I/O로 취득한다.
    Returns: (mincapacity, all_raw: pd.DataFrame|None, is_pne21_22: bool)
    """
    if (raw_file_path[-4:-1]) == "ter":
        return (mincapacity, None, False)

    mincapacity = pne_min_cap(raw_file_path, mincapacity, inirate)

    rawdir = raw_file_path + "\\Restore\\"
    if not os.path.isdir(rawdir):
        return (mincapacity, None, False)

    # 캐시에서 SaveEndData, file_index, subfile 조회
    save_end_data, file_index_list, subfile = _cached_pne_restore_files(raw_file_path)

    if save_end_data is None or file_index_list is None:
        return (mincapacity, None, False)

    # 파일 범위 결정
    if min_cycle != 1:
        index_min = save_end_data.loc[(save_end_data.loc[:, 27] == (min_cycle - 1)), 0].tolist()
    else:
        index_min = [0]
    index_max = save_end_data.loc[(save_end_data.loc[:, 27] == max_cycle), 0].tolist()
    if not index_max:
        index_max = save_end_data.loc[(save_end_data.loc[:, 27] == save_end_data.loc[:, 27].max()), 0].tolist()

    if len(index_min) == 0:
        file_start = 0
    else:
        file_start = binary_search(file_index_list, index_min[-1] + 1) - 1
    file_end = binary_search(file_index_list, index_max[-1]) - 1
    if file_start < 0:
        file_start = 0

    # SaveData 일괄 로딩
    _chunks = []
    for files in subfile[file_start:(file_end + 1)]:
        if "SaveData" in files:
            chunk = pd.read_csv(rawdir + files, sep=",", skiprows=0, engine="c",
                                header=None, encoding="cp949", on_bad_lines='skip')
            _chunks.append(chunk)
    all_raw = pd.concat(_chunks, ignore_index=True) if _chunks else None

    is_pne21_22 = is_micro_unit(raw_file_path)
    return (mincapacity, all_raw, is_pne21_22)


