                graph_set_profile((overall.index - x_min)/3600, overall.log_ECT_ISD_I / 1000, ax[1, 0], 0, 0, 0, "Time(hr)", "CurrAvg/ISD (A)", "", 2, xlim[0], xlim[1], xlim[2])
