        d_par2 = float(self.dTextEdit_2.text())
        e_par2 = float(self.eTextEdit_2.text())
        f_par2 = float(self.fTextEdit_2.text())
        a_par3 = float(self.aTextEdit_3.text())
        b_par3 = float(self.bTextEdit_3.text())
